import { createReadStream } from "node:fs";
import readline from "node:readline";
import type {
  CodexParsedTranscript,
  CodexSessionMetaRecord,
  CodexTranscriptMessage,
  CodexTranscriptRecord,
} from "../types/codex-transcript";
import { extractSessionSignals } from "./session-signals";
import { messageFromEvent, messageFromResponseItem } from "./transcript-parser/message-mappers";
import { parseTopLevelRecord } from "./transcript-parser/record-parsers";

interface TranscriptAccumulator {
  records: CodexTranscriptRecord[];
  messages: CodexTranscriptMessage[];
  malformedLineCount: number;
  skippedRecordCount: number;
  sessionMeta?: CodexSessionMetaRecord;
}

function createAccumulator(): TranscriptAccumulator {
  return {
    records: [],
    messages: [],
    malformedLineCount: 0,
    skippedRecordCount: 0,
  };
}

function collectRecord(
  accumulator: TranscriptAccumulator,
  record: CodexTranscriptRecord,
): TranscriptAccumulator {
  accumulator.records.push(record);

  if (record.recordType === "session_meta" && accumulator.sessionMeta === undefined) {
    accumulator.sessionMeta = record;
  }

  if (record.recordType === "event_msg") {
    const message = messageFromEvent(record);
    if (message) {
      accumulator.messages.push(message);
    }
  }

  // NOTE: response_item:message records are intentionally NOT collected as messages.
  // Codex transcripts emit every conversational message twice: once as event_msg
  // (user_message / agent_message) and once as response_item (type: "message").
  // Additionally, response_item includes non-conversational "developer" role messages
  // (system prompts, environment context) that inflate metrics.
  // We use event_msg as the sole message source to avoid duplication.
  // response_item records are still collected in accumulator.records for signal extraction.

  return accumulator;
}

export async function readTranscript(filePath: string): Promise<CodexParsedTranscript | null> {
  const stream = createReadStream(filePath, { encoding: "utf-8" });
  const lines = readline.createInterface({
    crlfDelay: Number.POSITIVE_INFINITY,
    input: stream,
  });

  let lineNumber = 0;
  const accumulator = createAccumulator();

  try {
    for await (const rawLine of lines) {
      lineNumber += 1;
      const line = rawLine.trim();
      if (line.length === 0) {
        continue;
      }

      let parsed: unknown;
      try {
        parsed = JSON.parse(line);
      } catch {
        accumulator.malformedLineCount += 1;
        continue;
      }

      const record = parseTopLevelRecord(parsed, lineNumber);
      if (record === null) {
        accumulator.skippedRecordCount += 1;
        continue;
      }

      collectRecord(accumulator, record);
    }
  } finally {
    lines.close();
    stream.destroy();
  }

  if (!accumulator.sessionMeta?.sessionId) {
    return null;
  }

  return {
    sessionId: accumulator.sessionMeta.sessionId,
    filePath,
    sessionMeta: accumulator.sessionMeta,
    records: accumulator.records,
    messages: accumulator.messages,
    signals: extractSessionSignals(accumulator.records),
    malformedLineCount: accumulator.malformedLineCount,
    skippedRecordCount: accumulator.skippedRecordCount,
  };
}

export async function readTranscripts(filePaths: string[]): Promise<CodexParsedTranscript[]> {
  const parsed = await Promise.all(filePaths.map((filePath) => readTranscript(filePath)));
  return parsed.filter((entry): entry is CodexParsedTranscript => entry !== null);
}
