/**
 * Generic Prompt Tag System
 *
 * This is a flexible tag system that can be used with any prompt type (practices, metrics, standup, etc.).
 * The optional `category` field helps organize tags logically without creating separate files.
 *
 * Currently focused on AI practices prompts, but easily extensible for future use cases.
 * When migrating to a proper `tags` table in the future, this single source of truth makes seeding straightforward.
 */

// Prompt tag type (defined without Zod to avoid pulling Zod into client bundles)
export type PromptTag = {
  id: string;
  displayName: string;
  description?: string;
  category?: string;
};

// Define all available prompt tags
// Generic system - tags can be used with any prompt type
export const PROMPT_TAGS = {
  // Currently focused on AI practices prompts, but flexible for future use
  TOP_5: {
    id: "top-5",
    displayName: "🕹️ Top 5",
    description: "Essential practices for maximum productivity",
    category: "practices",
  },
  ANALYZE_PROMPTS: {
    id: "analyze-prompts",
    displayName: "📈 Analyze my prompts",
    description: "Analyze your AI usage patterns and prompt effectiveness",
    category: "practices",
  },
  CHECKLISTS: {
    id: "checklists",
    displayName: "✅ Checklists",
    description: "Comprehensive checklists for common development tasks",
    category: "practices",
  },
  PROMPT_HACKS: {
    id: "prompt-hacks",
    displayName: "💬 Prompt Hacks",
    description: "Advanced techniques for better AI interactions",
    category: "practices",
  },
  AI_CODING_STACK: {
    id: "ai-coding-stack",
    displayName: "🤖 AI Coding Stack",
    description: "Tools and configurations for AI-assisted development",
    category: "practices",
  },

  // Future: Add more tags as needed for other prompt types
  // METRICS_TRACKING: { id: 'metrics-tracking', displayName: 'Metrics Tracking', category: 'metrics' },
  // STANDUP_SUMMARY: { id: 'standup-summary', displayName: 'Standup Summary', category: 'standup' },
} as const satisfies Record<string, PromptTag>;

export const AVAILABLE_PROMPT_TAGS = Object.values(PROMPT_TAGS);

// Extract valid tag IDs as a tuple for validation
const tagIds = AVAILABLE_PROMPT_TAGS.map((tag) => tag.id);
export const VALID_TAG_IDS = tagIds as [string, ...string[]];

// Helper to validate if a tag ID is valid (no Zod dependency)
export const isValidTagId = (tagId: string): boolean => {
  return AVAILABLE_PROMPT_TAGS.some((tag) => tag.id === tagId);
};

// Helper to get tag by ID (type-safe)
export const getTagById = (tagId: string): PromptTag | undefined => {
  return AVAILABLE_PROMPT_TAGS.find((tag) => tag.id === tagId);
};

// Helper to get tags by category
export const getTagsByCategory = (category: string): PromptTag[] => {
  return AVAILABLE_PROMPT_TAGS.filter((tag) => tag.category === category);
};

// Helper to get icon from tag's displayName
export const getTagIcon = (tagId: string): string => {
  const tag = getTagById(tagId);
  if (!tag) return "📝";

  // Extract emoji from displayName (format: "🕹️ Top 5")
  const match = tag.displayName.match(/^([\p{Emoji}]+)\s/u);
  return match?.[1] ?? "📝";
};

// Helper to get name without icon
export const getTagName = (tagId: string): string => {
  const tag = getTagById(tagId);
  if (!tag) return tagId;

  // Remove emoji from displayName
  return tag.displayName.replace(/^[\p{Emoji}]+\s*/u, "");
};
