import type {
  CodexCompactedRecord,
  CodexEventRecord,
  CodexResponseItemRecord,
  CodexSessionMetaRecord,
  CodexTranscriptRecord,
  CodexTurnContextRecord,
} from "../../types/codex-transcript";
import {
  parseCollaborationMode,
  parseDuration,
  parseGitContext,
  parseMessageContentBlocks,
  parseRateLimitWindow,
  parseSandboxPolicy,
  parseTokenUsage,
} from "./field-parsers";
import { isArray, isNonEmptyString, isNumber, isRecord, isString, toStringArray } from "./guards";

function parseSessionMetaRecord(
  payload: unknown,
  timestamp: string,
  lineNumber: number,
): CodexSessionMetaRecord | null {
  if (
    !isRecord(payload) ||
    !isNonEmptyString(payload.id) ||
    !isNonEmptyString(payload.cwd) ||
    !isNonEmptyString(payload.originator) ||
    !isNonEmptyString(payload.source) ||
    !isNonEmptyString(payload.cli_version) ||
    !isNonEmptyString(payload.model_provider)
  ) {
    return null;
  }

  const git = parseGitContext(payload.git);

  return {
    recordType: "session_meta",
    lineNumber,
    timestamp,
    sessionId: payload.id,
    cwd: payload.cwd,
    originator: payload.originator,
    source: payload.source,
    cliVersion: payload.cli_version,
    modelProvider: payload.model_provider,
    ...(git ? { git } : {}),
  };
}

function parseEventRecord(
  payload: unknown,
  timestamp: string,
  lineNumber: number,
): CodexEventRecord | null {
  if (!isRecord(payload) || !isNonEmptyString(payload.type)) {
    return null;
  }

  switch (payload.type) {
    case "task_started":
      if (!isNonEmptyString(payload.turn_id)) {
        return null;
      }
      return {
        recordType: "event_msg",
        eventType: "task_started",
        lineNumber,
        timestamp,
        turnId: payload.turn_id,
        ...(isNumber(payload.model_context_window)
          ? { modelContextWindow: payload.model_context_window }
          : {}),
        ...(isNonEmptyString(payload.collaboration_mode_kind)
          ? { collaborationModeKind: payload.collaboration_mode_kind }
          : {}),
      };
    case "task_complete":
      if (!isNonEmptyString(payload.turn_id)) {
        return null;
      }
      return {
        recordType: "event_msg",
        eventType: "task_complete",
        lineNumber,
        timestamp,
        turnId: payload.turn_id,
        ...(isString(payload.last_agent_message)
          ? { lastAgentMessage: payload.last_agent_message }
          : {}),
      };
    case "turn_aborted":
      if (!isNonEmptyString(payload.turn_id)) {
        return null;
      }
      return {
        recordType: "event_msg",
        eventType: "turn_aborted",
        lineNumber,
        timestamp,
        turnId: payload.turn_id,
        ...(isNonEmptyString(payload.reason) ? { reason: payload.reason } : {}),
      };
    case "user_message":
      if (!isString(payload.message)) {
        return null;
      }
      return {
        recordType: "event_msg",
        eventType: "user_message",
        lineNumber,
        timestamp,
        message: payload.message,
        imagesCount: isArray(payload.images) ? payload.images.length : 0,
        localImagesCount: isArray(payload.local_images) ? payload.local_images.length : 0,
        textElements: toStringArray(payload.text_elements),
      };
    case "agent_message":
      if (!isString(payload.message)) {
        return null;
      }
      return {
        recordType: "event_msg",
        eventType: "agent_message",
        lineNumber,
        timestamp,
        message: payload.message,
        ...(isNonEmptyString(payload.phase) ? { phase: payload.phase } : {}),
        hasMemoryCitation:
          payload.memory_citation !== null && payload.memory_citation !== undefined,
      };
    case "token_count": {
      const info = isRecord(payload.info)
        ? {
            ...(parseTokenUsage(payload.info.total_token_usage)
              ? { totalTokenUsage: parseTokenUsage(payload.info.total_token_usage) }
              : {}),
            ...(parseTokenUsage(payload.info.last_token_usage)
              ? { lastTokenUsage: parseTokenUsage(payload.info.last_token_usage) }
              : {}),
            ...(isNumber(payload.info.model_context_window)
              ? { modelContextWindow: payload.info.model_context_window }
              : {}),
          }
        : undefined;
      const rateLimits = isRecord(payload.rate_limits)
        ? {
            ...(isNonEmptyString(payload.rate_limits.limit_id)
              ? { limitId: payload.rate_limits.limit_id }
              : {}),
            ...(isNonEmptyString(payload.rate_limits.plan_type)
              ? { planType: payload.rate_limits.plan_type }
              : {}),
            ...(parseRateLimitWindow(payload.rate_limits.primary)
              ? { primary: parseRateLimitWindow(payload.rate_limits.primary) }
              : {}),
            ...(parseRateLimitWindow(payload.rate_limits.secondary)
              ? { secondary: parseRateLimitWindow(payload.rate_limits.secondary) }
              : {}),
          }
        : undefined;

      return {
        recordType: "event_msg",
        eventType: "token_count",
        lineNumber,
        timestamp,
        ...(info && Object.keys(info).length > 0 ? { info } : {}),
        ...(rateLimits && Object.keys(rateLimits).length > 0 ? { rateLimits } : {}),
      };
    }
    case "exec_command_end": {
      if (!isArray(payload.command)) {
        return null;
      }
      const duration = parseDuration(payload.duration);
      return {
        recordType: "event_msg",
        eventType: "exec_command_end",
        lineNumber,
        timestamp,
        command: toStringArray(payload.command),
        parsedCmd: toStringArray(payload.parsed_cmd),
        ...(isNonEmptyString(payload.call_id) ? { callId: payload.call_id } : {}),
        ...(isNonEmptyString(payload.turn_id) ? { turnId: payload.turn_id } : {}),
        ...(isNonEmptyString(payload.cwd) ? { cwd: payload.cwd } : {}),
        ...(isNumber(payload.exit_code) ? { exitCode: payload.exit_code } : {}),
        ...(isNonEmptyString(payload.status) ? { status: payload.status } : {}),
        ...(duration ? { duration } : {}),
      };
    }
    case "mcp_tool_call_end": {
      const invocation = isRecord(payload.invocation) ? payload.invocation : undefined;
      if (
        !invocation ||
        !isNonEmptyString(invocation.server) ||
        !isNonEmptyString(invocation.tool)
      ) {
        return null;
      }

      const duration = parseDuration(payload.duration);
      const resultKind = isRecord(payload.result)
        ? "Ok" in payload.result
          ? "ok"
          : "Err" in payload.result
            ? "err"
            : undefined
        : undefined;

      return {
        recordType: "event_msg",
        eventType: "mcp_tool_call_end",
        lineNumber,
        timestamp,
        server: invocation.server,
        tool: invocation.tool,
        ...(isNonEmptyString(payload.call_id) ? { callId: payload.call_id } : {}),
        ...(duration ? { duration } : {}),
        ...(resultKind ? { resultKind } : {}),
      };
    }
    case "item_completed": {
      const item = isRecord(payload.item) ? payload.item : undefined;
      return {
        recordType: "event_msg",
        eventType: "item_completed",
        lineNumber,
        timestamp,
        ...(isNonEmptyString(payload.thread_id) ? { threadId: payload.thread_id } : {}),
        ...(isNonEmptyString(payload.turn_id) ? { turnId: payload.turn_id } : {}),
        ...(item && isNonEmptyString(item.type) ? { itemType: item.type } : {}),
        ...(item && isNonEmptyString(item.id) ? { itemId: item.id } : {}),
      };
    }
    case "context_compacted":
      return {
        recordType: "event_msg",
        eventType: "context_compacted",
        lineNumber,
        timestamp,
      };
    case "thread_rolled_back":
      return {
        recordType: "event_msg",
        eventType: "thread_rolled_back",
        lineNumber,
        timestamp,
        ...(isNumber(payload.num_turns) ? { numTurns: payload.num_turns } : {}),
      };
    default:
      return null;
  }
}

function parseResponseItemRecord(
  payload: unknown,
  timestamp: string,
  lineNumber: number,
): CodexResponseItemRecord | null {
  if (!isRecord(payload) || !isNonEmptyString(payload.type)) {
    return null;
  }

  switch (payload.type) {
    case "message": {
      if (!isNonEmptyString(payload.role)) {
        return null;
      }
      const content = parseMessageContentBlocks(payload.content);
      if (content === null) {
        return null;
      }
      return {
        recordType: "response_item",
        itemType: "message",
        lineNumber,
        timestamp,
        role: payload.role,
        content,
        ...(isNonEmptyString(payload.phase) ? { phase: payload.phase } : {}),
      };
    }
    case "reasoning": {
      const summary = isArray(payload.summary)
        ? payload.summary
            .filter(isRecord)
            .map((entry) => (isString(entry.text) ? entry.text : null))
            .filter((entry): entry is string => entry !== null)
        : [];
      return {
        recordType: "response_item",
        itemType: "reasoning",
        lineNumber,
        timestamp,
        summaryText: summary,
        hasEncryptedContent: isNonEmptyString(payload.encrypted_content),
      };
    }
    case "function_call":
      if (
        !isNonEmptyString(payload.name) ||
        !isNonEmptyString(payload.call_id) ||
        !isString(payload.arguments)
      ) {
        return null;
      }
      return {
        recordType: "response_item",
        itemType: "function_call",
        lineNumber,
        timestamp,
        name: payload.name,
        callId: payload.call_id,
        arguments: payload.arguments,
      };
    case "function_call_output":
      if (!isNonEmptyString(payload.call_id) || !isString(payload.output)) {
        return null;
      }
      return {
        recordType: "response_item",
        itemType: "function_call_output",
        lineNumber,
        timestamp,
        callId: payload.call_id,
        output: payload.output,
      };
    case "custom_tool_call":
      if (
        !isNonEmptyString(payload.call_id) ||
        !isNonEmptyString(payload.name) ||
        !isString(payload.input)
      ) {
        return null;
      }
      return {
        recordType: "response_item",
        itemType: "custom_tool_call",
        lineNumber,
        timestamp,
        callId: payload.call_id,
        name: payload.name,
        input: payload.input,
        ...(isNonEmptyString(payload.status) ? { status: payload.status } : {}),
      };
    case "custom_tool_call_output":
      if (!isNonEmptyString(payload.call_id) || !isString(payload.output)) {
        return null;
      }
      return {
        recordType: "response_item",
        itemType: "custom_tool_call_output",
        lineNumber,
        timestamp,
        callId: payload.call_id,
        output: payload.output,
      };
    case "web_search_call": {
      const action = isRecord(payload.action) ? payload.action : undefined;
      return {
        recordType: "response_item",
        itemType: "web_search_call",
        lineNumber,
        timestamp,
        queries: action ? toStringArray(action.queries) : [],
        ...(isNonEmptyString(payload.status) ? { status: payload.status } : {}),
        ...(action && isNonEmptyString(action.type) ? { actionType: action.type } : {}),
        ...(action && isNonEmptyString(action.query) ? { query: action.query } : {}),
      };
    }
    default:
      return null;
  }
}

function parseTurnContextRecord(
  payload: unknown,
  timestamp: string,
  lineNumber: number,
): CodexTurnContextRecord | null {
  if (!isRecord(payload) || !isNonEmptyString(payload.turn_id) || !isNonEmptyString(payload.cwd)) {
    return null;
  }

  const sandboxPolicy = parseSandboxPolicy(payload.sandbox_policy);
  const collaborationMode = parseCollaborationMode(payload.collaboration_mode);

  return {
    recordType: "turn_context",
    lineNumber,
    timestamp,
    turnId: payload.turn_id,
    cwd: payload.cwd,
    ...(isNonEmptyString(payload.current_date) ? { currentDate: payload.current_date } : {}),
    ...(isNonEmptyString(payload.timezone) ? { timezone: payload.timezone } : {}),
    ...(isNonEmptyString(payload.approval_policy)
      ? { approvalPolicy: payload.approval_policy }
      : {}),
    ...(sandboxPolicy ? { sandboxPolicy } : {}),
    ...(isNonEmptyString(payload.model) ? { model: payload.model } : {}),
    ...(isNonEmptyString(payload.personality) ? { personality: payload.personality } : {}),
    ...(collaborationMode ? { collaborationMode } : {}),
    ...(isNonEmptyString(payload.effort) ? { effort: payload.effort } : {}),
    ...(isNonEmptyString(payload.summary) ? { summary: payload.summary } : {}),
    ...(isRecord(payload.truncation_policy)
      ? {
          truncationPolicy: {
            ...(isNonEmptyString(payload.truncation_policy.mode)
              ? { mode: payload.truncation_policy.mode }
              : {}),
            ...(isNumber(payload.truncation_policy.limit)
              ? { limit: payload.truncation_policy.limit }
              : {}),
          },
        }
      : {}),
  };
}

function parseCompactedRecord(
  payload: unknown,
  timestamp: string,
  lineNumber: number,
): CodexCompactedRecord | null {
  if (!isRecord(payload)) {
    return null;
  }

  return {
    recordType: "compacted",
    lineNumber,
    timestamp,
    replacementHistoryCount: isArray(payload.replacement_history)
      ? payload.replacement_history.length
      : 0,
  };
}

export function parseTopLevelRecord(
  value: unknown,
  lineNumber: number,
): CodexTranscriptRecord | null {
  if (!isRecord(value) || !isNonEmptyString(value.type) || !isNonEmptyString(value.timestamp)) {
    return null;
  }

  switch (value.type) {
    case "session_meta":
      return parseSessionMetaRecord(value.payload, value.timestamp, lineNumber);
    case "event_msg":
      return parseEventRecord(value.payload, value.timestamp, lineNumber);
    case "response_item":
      return parseResponseItemRecord(value.payload, value.timestamp, lineNumber);
    case "turn_context":
      return parseTurnContextRecord(value.payload, value.timestamp, lineNumber);
    case "compacted":
      return parseCompactedRecord(value.payload, value.timestamp, lineNumber);
    default:
      return null;
  }
}
