import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";
import pluginManifest from "../../.codex-plugin/plugin.json";
import { type LoginResult, loginWithDeviceFlow } from "../auth/login";
import { clearAuthSession, loadAuthSession } from "../auth/session";
import { formatExclusionReason } from "../privacy/sanitize";
import { runSync, type SyncResponse } from "../sync/sync";
import { getBestEffortUpdateMetadata, type UpdateMetadata } from "../update/check";
import { loadWorkspaceBinding, saveActiveWorkspaceBinding } from "../workspace/binding";

export const ZEST_CODEX_SERVER_NAME = pluginManifest.name;
export const ZEST_CODEX_SERVICE_ID = pluginManifest.name;
export const ZEST_CODEX_PLUGIN_VERSION = pluginManifest.version;

const workspaceInputSchema = {
  workspaceId: z.string().trim().min(1).optional(),
};

export type HealthResponse = {
  service: string;
  status: "ok";
  version: string;
};

export type PrivacyResponse = {
  mode: "local_redaction";
  redaction: {
    appliesBeforeQueue: true;
    appliesBeforeUpload: true;
    excludesDeniedSources: true;
  };
  sources: {
    allowed: ["transcript"];
    deniedBehavior: "drop";
    transcriptPaths: [
      "~/.codex/session_index.jsonl",
      "~/.codex/history.jsonl",
      "~/.codex/sessions/**/*.jsonl",
    ];
  };
  summary: {
    exclusionReasonFormatting: ReturnType<typeof formatExclusionReason>;
    runtimeConfigurable: false;
    secretsExposed: false;
  };
};

export type WorkspaceResponse = {
  authenticated: boolean;
  status: "bound" | "unbound";
  updated?: boolean;
  workspace?: {
    id: string;
    name?: string;
  };
};

export type LogoutResponse = {
  clearedAuth: true;
  preservedQueueState: true;
  preservedWorkspaceBinding: boolean;
  status: "logged_out";
};

export type ToolResponseWithOptionalUpdate<T extends Record<string, unknown>> = T & {
  update?: UpdateMetadata;
};

export type CreateServerOptions = {
  login?: () => Promise<LoginResult>;
  logout?: () => Promise<LogoutResponse>;
  name?: string;
  privacy?: () => Promise<PrivacyResponse>;
  sync?: () => Promise<SyncResponse>;
  status?: () => Promise<StatusResponse>;
  service?: string;
  updateCheck?: () => Promise<UpdateMetadata | null>;
  version?: string;
  workspace?: (input?: { workspaceId?: string }) => Promise<WorkspaceResponse>;
};

export type StatusResponse = {
  authenticated: boolean;
  version: string;
  user?: {
    email: string;
    id: string;
  };
  workspace?: {
    id: string;
    name?: string;
  };
  sync: {
    ready: boolean;
    reason?: "logged_out" | "workspace_unbound";
  };
};

function createToolResult<T extends Record<string, unknown>>(
  result: ToolResponseWithOptionalUpdate<T>,
): {
  content: Array<{ text: string; type: "text" }>;
  structuredContent: ToolResponseWithOptionalUpdate<T>;
} {
  return {
    content: [
      {
        text: JSON.stringify(result),
        type: "text",
      },
    ],
    structuredContent: result,
  };
}

async function attachUpdateMetadata<T extends Record<string, unknown>>(
  result: T,
  updateCheck?: () => Promise<UpdateMetadata | null>,
): Promise<ToolResponseWithOptionalUpdate<T>> {
  if (!updateCheck) {
    return result;
  }

  const update = await updateCheck();

  if (!update) {
    return result;
  }

  return {
    ...result,
    update,
  };
}

export async function createStatusResponse(): Promise<StatusResponse> {
  const authSession = await loadAuthSession();

  if (!authSession) {
    return {
      authenticated: false,
      version: ZEST_CODEX_PLUGIN_VERSION,
      sync: {
        ready: false,
        reason: "logged_out",
      },
    };
  }

  const workspaceBinding = await loadWorkspaceBinding();

  if (!workspaceBinding) {
    return {
      authenticated: true,
      version: ZEST_CODEX_PLUGIN_VERSION,
      sync: {
        ready: false,
        reason: "workspace_unbound",
      },
      user: {
        email: authSession.email,
        id: authSession.userId,
      },
    };
  }

  return {
    authenticated: true,
    version: ZEST_CODEX_PLUGIN_VERSION,
    sync: {
      ready: true,
    },
    user: {
      email: authSession.email,
      id: authSession.userId,
    },
    workspace: {
      id: workspaceBinding.active.id,
      ...(workspaceBinding.active.name ? { name: workspaceBinding.active.name } : {}),
    },
  };
}

export async function createPrivacyResponse(): Promise<PrivacyResponse> {
  return {
    mode: "local_redaction",
    redaction: {
      appliesBeforeQueue: true,
      appliesBeforeUpload: true,
      excludesDeniedSources: true,
    },
    sources: {
      allowed: ["transcript"],
      deniedBehavior: "drop",
      transcriptPaths: [
        "~/.codex/session_index.jsonl",
        "~/.codex/history.jsonl",
        "~/.codex/sessions/**/*.jsonl",
      ],
    },
    summary: {
      exclusionReasonFormatting: formatExclusionReason(undefined),
      runtimeConfigurable: false,
      secretsExposed: false,
    },
  };
}

export async function createWorkspaceResponse(input?: {
  workspaceId?: string;
}): Promise<WorkspaceResponse> {
  if (input?.workspaceId !== undefined) {
    const trimmedWorkspaceId = input.workspaceId.trim();

    if (trimmedWorkspaceId.length === 0) {
      throw new Error("workspaceId must be a non-empty string");
    }

    await saveActiveWorkspaceBinding(trimmedWorkspaceId);
  }

  const [authSession, workspaceBinding] = await Promise.all([
    loadAuthSession(),
    loadWorkspaceBinding(),
  ]);

  if (!workspaceBinding) {
    return {
      authenticated: authSession !== null,
      ...(input?.workspaceId !== undefined ? { updated: true } : {}),
      status: "unbound",
    };
  }

  return {
    authenticated: authSession !== null,
    status: "bound",
    ...(input?.workspaceId !== undefined ? { updated: true } : {}),
    workspace: {
      id: workspaceBinding.active.id,
      ...(workspaceBinding.active.name ? { name: workspaceBinding.active.name } : {}),
    },
  };
}

export async function createLogoutResponse(): Promise<LogoutResponse> {
  const workspaceBinding = await loadWorkspaceBinding();

  await clearAuthSession();

  return {
    clearedAuth: true,
    preservedQueueState: true,
    preservedWorkspaceBinding: workspaceBinding !== null,
    status: "logged_out",
  };
}

function assertRequiredOption(label: string, value: string): string {
  const trimmedValue = value.trim();

  if (trimmedValue.length === 0) {
    throw new Error(`Missing required MCP server ${label}`);
  }

  return trimmedValue;
}

export function createHealthResponse(options: CreateServerOptions = {}): HealthResponse {
  return {
    service: assertRequiredOption("service", options.service ?? ZEST_CODEX_SERVICE_ID),
    status: "ok",
    version: assertRequiredOption("version", options.version ?? ZEST_CODEX_PLUGIN_VERSION),
  };
}

export function createServer(options: CreateServerOptions = {}): McpServer {
  const name = assertRequiredOption("name", options.name ?? ZEST_CODEX_SERVER_NAME);
  const healthResponse = createHealthResponse(options);
  const login = options.login ?? (() => loginWithDeviceFlow());
  const logout = options.logout ?? (() => createLogoutResponse());
  const privacy = options.privacy ?? (() => createPrivacyResponse());
  const status = options.status ?? (() => createStatusResponse());
  const sync = options.sync ?? (() => runSync());
  const updateCheck =
    options.updateCheck ??
    (() => getBestEffortUpdateMetadata({ currentVersion: healthResponse.version }));
  const workspace = options.workspace ?? ((input) => createWorkspaceResponse(input));
  const server = new McpServer({
    name,
    version: healthResponse.version,
  });

  server.registerTool(
    "health",
    {
      description: "Report basic MCP server availability for the Zest Codex plugin.",
      title: "Zest Health",
    },
    async () => createToolResult(await attachUpdateMetadata(healthResponse, updateCheck)),
  );

  server.registerTool(
    "login",
    {
      description: "Authenticate the Codex plugin with Zest using the browser-based device flow.",
      title: "Zest Login",
    },
    async () => {
      const result = (await login()) as unknown as Record<string, unknown>;
      return createToolResult(await attachUpdateMetadata(result, updateCheck));
    },
  );

  server.registerTool(
    "status",
    {
      description:
        "Report authentication, workspace binding, and basic sync readiness for the Zest Codex plugin.",
      title: "Zest Status",
    },
    async () => {
      return createToolResult(await attachUpdateMetadata(await status(), updateCheck));
    },
  );

  server.registerTool(
    "sync",
    {
      description:
        "Collect allowlisted Codex transcripts, apply privacy filtering, queue sanitized payloads, and upload when possible.",
      title: "Zest Sync",
    },
    async () => {
      const result = await sync();
      return createToolResult(result as unknown as Record<string, unknown>);
    },
  );

  server.registerTool(
    "privacy",
    {
      description:
        "Inspect the active local privacy filtering and exclusion behavior for the Zest Codex plugin.",
      title: "Zest Privacy",
    },
    async () => {
      return createToolResult(await attachUpdateMetadata(await privacy(), updateCheck));
    },
  );

  server.registerTool(
    "workspace",
    {
      description:
        "Show the current Zest workspace binding or set a new active workspaceId for future syncs.",
      inputSchema: workspaceInputSchema,
      title: "Zest Workspace",
    },
    async (input) => {
      return createToolResult(await attachUpdateMetadata(await workspace(input), updateCheck));
    },
  );

  server.registerTool(
    "logout",
    {
      description:
        "Clear the local Zest authentication session while preserving workspace binding and queued payload state.",
      title: "Zest Logout",
    },
    async () => {
      return createToolResult(
        await attachUpdateMetadata(
          (await logout()) as unknown as Record<string, unknown>,
          updateCheck,
        ),
      );
    },
  );

  return server;
}

export async function startServer(options: CreateServerOptions = {}): Promise<McpServer> {
  const server = createServer(options);
  const transport = new StdioServerTransport();

  await server.connect(transport);

  return server;
}
