import type { SupabaseClient } from "@supabase/supabase-js";
import type { Database } from "@zest/types/database";
import { loadAuthSession, type PersistedAuthSession } from "../auth/session";
import { SYNC_DEBUG_LOGGING_ENABLED } from "../config/constants";
import { appendTextFile } from "../state/files";
import { resolveDefaultStatePath } from "../state/paths";
import { createOnDemandClient, type OnDemandClient } from "../supabase/client";
import { DataControlsProvider } from "../supabase/data-controls-provider";
import type { ChatMessageInsert, ChatSessionInsert, CodexQueueEntry } from "../types/zest-payload";
import { loadWorkspaceBinding, type PersistedWorkspaceBinding } from "../workspace/binding";
import {
  getReplayableQueueEntries,
  markQueueEntriesRetrying,
  markQueueEntriesSynced,
  recordQueueFailure,
} from "./queue";

export type CodexSyncErrorType =
  | "not_authenticated"
  | "workspace_unbound"
  | "data_controls_unavailable"
  | "network_error"
  | "upload_failed";

export interface UploadQueuedTranscriptsResult {
  success: boolean;
  uploaded: {
    messages: number;
    sessions: number;
  };
  error?: string;
  errorType?: CodexSyncErrorType;
}

export interface UploadQueuedTranscriptsDependencies {
  createClient?: () => Promise<OnDemandClient | null>;
  dataControls?: DataControlsProvider;
  getQueueEntries?: () => Promise<CodexQueueEntry[]>;
  loadSession?: () => Promise<PersistedAuthSession | null>;
  loadWorkspace?: () => Promise<PersistedWorkspaceBinding | null>;
  markRetrying?: (ids: string[], error?: string | null, now?: Date) => Promise<CodexQueueEntry[]>;
  markSynced?: (ids: string[]) => Promise<CodexQueueEntry[]>;
  now?: () => Date;
  recordFailure?: (ids: string[], error: string, now?: Date) => Promise<CodexQueueEntry[]>;
}

type ChatMessageUpsert = Omit<ChatMessageInsert, "id">;

const defaultDataControls = new DataControlsProvider();
const DEBUG_SYNC_LOG_PATH = resolveDefaultStatePath("logs", "sync-debug.log");

async function debugSyncLog(message: string, details?: Record<string, unknown>): Promise<void> {
  if (!SYNC_DEBUG_LOGGING_ENABLED) {
    return;
  }

  const line = `${new Date().toISOString()} ${message}${details ? ` ${JSON.stringify(details)}` : ""}\n`;
  await appendTextFile(DEBUG_SYNC_LOG_PATH, line);
}

function isNetworkError(error: unknown): boolean {
  if (!(error instanceof Error)) {
    return false;
  }

  const message = error.message.toLowerCase();
  const code = (error as NodeJS.ErrnoException).code;

  return (
    message.includes("network") ||
    message.includes("timeout") ||
    message.includes("fetch") ||
    ["ENOTFOUND", "ECONNREFUSED", "ECONNRESET", "ETIMEDOUT", "ENETUNREACH"].includes(code ?? "")
  );
}

function deduplicateSessions(
  entries: CodexQueueEntry[],
  workspaceId: string,
  allowedSessionIds?: Set<string>,
): ChatSessionInsert[] {
  const sessionsById = new Map<string, ChatSessionInsert>();

  for (const entry of entries) {
    const session = entry.payload.payload.session;
    if (!session.id) {
      continue;
    }

    if (allowedSessionIds && !allowedSessionIds.has(session.id)) {
      continue;
    }

    sessionsById.set(session.id, {
      ...session,
      workspace_id: workspaceId,
    });
  }

  return Array.from(sessionsById.values());
}

function deduplicateMessages(entries: CodexQueueEntry[]): ChatMessageUpsert[] {
  const messagesByKey = new Map<string, ChatMessageUpsert>();

  for (const entry of entries) {
    for (const message of entry.payload.payload.messages) {
      const { id: _id, ...messageWithoutId } = message;
      const key = `${messageWithoutId.session_id}:${messageWithoutId.message_index}`;
      messagesByKey.set(key, messageWithoutId);
    }
  }

  return Array.from(messagesByKey.values());
}

function filterMessagesForUpload(
  messages: ChatMessageUpsert[],
  dataControls: DataControlsProvider,
): ChatMessageUpsert[] {
  const shouldUploadUserMessages = dataControls.shouldUploadUserMessages();
  const shouldUploadAssistantMessages = dataControls.shouldUploadAssistantMessages();
  const shouldUploadCodeDiffs = dataControls.shouldUploadCodeDiffs();

  return messages
    .filter((message) => {
      if (message.role === "user") {
        return shouldUploadUserMessages;
      }

      if (message.role === "assistant") {
        return shouldUploadAssistantMessages;
      }

      return true;
    })
    .map((message) => (shouldUploadCodeDiffs ? message : { ...message, code_diffs: null }));
}

async function upsertSessions(
  client: SupabaseClient<Database>,
  sessions: ChatSessionInsert[],
): Promise<void> {
  if (sessions.length === 0) {
    return;
  }

  const { error } = await client.from("chat_sessions").upsert(sessions, { onConflict: "id" });
  if (error) {
    throw error;
  }
}

async function upsertMessages(
  client: SupabaseClient<Database>,
  messages: ChatMessageUpsert[],
): Promise<void> {
  if (messages.length === 0) {
    return;
  }

  const { error } = await client
    .from("chat_messages")
    .upsert(messages, { onConflict: "session_id,message_index" });

  if (error) {
    throw error;
  }
}

export async function uploadQueuedTranscripts(
  dependencies: UploadQueuedTranscriptsDependencies = {},
): Promise<UploadQueuedTranscriptsResult> {
  const loadSession = dependencies.loadSession ?? loadAuthSession;
  const loadWorkspace = dependencies.loadWorkspace ?? loadWorkspaceBinding;
  const getQueueEntries = dependencies.getQueueEntries ?? getReplayableQueueEntries;
  const createClient = dependencies.createClient ?? (() => createOnDemandClient());
  const dataControls = dependencies.dataControls ?? defaultDataControls;
  const markRetrying = dependencies.markRetrying ?? markQueueEntriesRetrying;
  const recordFailure = dependencies.recordFailure ?? recordQueueFailure;
  const markSynced = dependencies.markSynced ?? markQueueEntriesSynced;
  const now = dependencies.now ?? (() => new Date());

  const session = await loadSession();
  if (!session) {
    return {
      success: false,
      uploaded: { messages: 0, sessions: 0 },
      error: "Sync failed: not authenticated",
      errorType: "not_authenticated",
    };
  }

  const workspace = await loadWorkspace();
  if (!workspace) {
    return {
      success: false,
      uploaded: { messages: 0, sessions: 0 },
      error: "Sync failed: workspace unbound",
      errorType: "workspace_unbound",
    };
  }

  const queuedEntries = await getQueueEntries();
  if (queuedEntries.length === 0) {
    return {
      success: true,
      uploaded: { messages: 0, sessions: 0 },
    };
  }

  const onDemand = await createClient();
  if (!onDemand) {
    return {
      success: false,
      uploaded: { messages: 0, sessions: 0 },
      error: "Sync failed: not authenticated",
      errorType: "not_authenticated",
    };
  }

  const ids = queuedEntries.map((entry) => entry.id);

  try {
    if (!dataControls.isReady() || dataControls.isStale(now().getTime())) {
      await debugSyncLog("refreshing data controls", {
        hasCachedControls: dataControls.isReady(),
        isStale: dataControls.isStale(now().getTime()),
        queuedEntries: queuedEntries.length,
        userId: session.userId,
        workspaceId: workspace.active.id,
      });
      const refreshed = await dataControls.refresh(
        onDemand.client,
        workspace.active.id,
        session.userId,
        now().getTime(),
      );

      if (!refreshed || !dataControls.isReady()) {
        await debugSyncLog("data controls unavailable; blocking upload", {
          queuedEntries: queuedEntries.length,
          userId: session.userId,
          workspaceId: workspace.active.id,
        });
        return {
          success: false,
          uploaded: { messages: 0, sessions: 0 },
          error: "Sync failed: data controls unavailable",
          errorType: "data_controls_unavailable",
        };
      }
    } else {
      await debugSyncLog("using cached data controls", {
        queuedEntries: queuedEntries.length,
        userId: session.userId,
        workspaceId: workspace.active.id,
      });
    }

    const filteredMessages = filterMessagesForUpload(
      deduplicateMessages(queuedEntries),
      dataControls,
    );
    await debugSyncLog("filtered queued payloads for upload", {
      queuedEntries: queuedEntries.length,
      filteredMessages: filteredMessages.length,
      uploadAssistantMessages: dataControls.shouldUploadAssistantMessages(),
      uploadCodeDiffs: dataControls.shouldUploadCodeDiffs(),
      uploadUserMessages: dataControls.shouldUploadUserMessages(),
    });
    if (filteredMessages.length === 0) {
      await debugSyncLog("no messages allowed by data controls; skipping backend writes", {
        queuedEntries: queuedEntries.length,
      });
      return {
        success: true,
        uploaded: {
          messages: 0,
          sessions: 0,
        },
      };
    }

    const allowedSessionIds = new Set(
      queuedEntries
        .filter((entry) => entry.payload.payload.messages.length === 0)
        .map((entry) => entry.payload.payload.session.id)
        .filter((sessionId): sessionId is string => Boolean(sessionId)),
    );
    for (const message of filteredMessages) {
      allowedSessionIds.add(message.session_id);
    }
    const sessions = deduplicateSessions(queuedEntries, workspace.active.id, allowedSessionIds);
    const attemptTime = now();

    await debugSyncLog("uploading queued payloads", {
      messages: filteredMessages.length,
      sessions: sessions.length,
      workspaceId: workspace.active.id,
    });
    await markRetrying(ids, null, attemptTime);

    await upsertSessions(onDemand.client, sessions);
    await upsertMessages(onDemand.client, filteredMessages);
    await markSynced(ids);

    await debugSyncLog("upload completed", {
      messages: filteredMessages.length,
      sessions: sessions.length,
    });

    return {
      success: true,
      uploaded: {
        messages: filteredMessages.length,
        sessions: sessions.length,
      },
    };
  } catch (error) {
    const errorType = isNetworkError(error) ? "network_error" : "upload_failed";
    const message = error instanceof Error ? error.message : "Upload failed";

    await debugSyncLog("upload failed", {
      errorType,
      message,
      queuedEntries: queuedEntries.length,
    });
    await recordFailure(ids, message, now());

    return {
      success: false,
      uploaded: { messages: 0, sessions: 0 },
      error: message,
      errorType,
    };
  } finally {
    await onDemand.dispose();
  }
}
