import { readJsonFile, writeJsonFileAtomic } from "../state/files";
import { resolveStatePath } from "../state/paths";
import type {
  CodexDroppedTranscriptPayload,
  CodexQueuedTranscriptPayload,
  CodexQueueEntry,
  CodexQueueStats,
  CodexSanitizedPayloadResult,
} from "../types/zest-payload";

export const MAX_RETRY_ATTEMPTS = 3;

function getNowIso(now = new Date()): string {
  return now.toISOString();
}

function resolveQueueFilePath(): string {
  return resolveStatePath("queue", "transcripts.json");
}

function sortQueueEntries(entries: CodexQueueEntry[]): CodexQueueEntry[] {
  return [...entries].sort(
    (left, right) =>
      left.createdAt.localeCompare(right.createdAt) || left.id.localeCompare(right.id),
  );
}

function dedupeDroppedPayloads(
  results: CodexSanitizedPayloadResult[],
): CodexQueuedTranscriptPayload[] {
  return results.filter(
    (result): result is Exclude<CodexSanitizedPayloadResult, CodexDroppedTranscriptPayload> =>
      result.status === "sanitized",
  );
}

export function getQueueFilePath(): string {
  return resolveQueueFilePath();
}

export function createQueueEntry(
  payload: CodexQueuedTranscriptPayload,
  now = new Date(),
): CodexQueueEntry {
  const timestamp = getNowIso(now);
  const id = payload.payload.session.id;

  if (!id) {
    throw new Error("Queue entries require a session id");
  }

  return {
    id,
    dedupeKey: id,
    status: "pending",
    attemptCount: 0,
    lastAttemptAt: null,
    lastFailureAt: null,
    lastError: null,
    createdAt: timestamp,
    updatedAt: timestamp,
    payload,
  };
}

export function buildQueueEntriesFromResults(
  results: CodexSanitizedPayloadResult[],
  existingEntries: CodexQueueEntry[] = [],
  now = new Date(),
): CodexQueueEntry[] {
  const existingKeys = new Set(existingEntries.map((entry) => entry.dedupeKey));
  const nextEntries = [...existingEntries];

  for (const payload of dedupeDroppedPayloads(results)) {
    const entry = createQueueEntry(payload, now);
    if (existingKeys.has(entry.dedupeKey)) {
      continue;
    }

    existingKeys.add(entry.dedupeKey);
    nextEntries.push(entry);
  }

  return sortQueueEntries(nextEntries);
}

export async function loadQueueEntries(): Promise<CodexQueueEntry[]> {
  const entries = await readJsonFile<CodexQueueEntry[]>(resolveQueueFilePath());
  return sortQueueEntries(entries ?? []);
}

export async function saveQueueEntries(entries: CodexQueueEntry[]): Promise<void> {
  await writeJsonFileAtomic(resolveQueueFilePath(), sortQueueEntries(entries));
}

export async function enqueueSanitizedPayloads(
  results: CodexSanitizedPayloadResult[],
  now = new Date(),
): Promise<CodexQueueEntry[]> {
  const existingEntries = await loadQueueEntries();
  const nextEntries = buildQueueEntriesFromResults(results, existingEntries, now);
  await saveQueueEntries(nextEntries);
  return nextEntries;
}

export async function getReplayableQueueEntries(): Promise<CodexQueueEntry[]> {
  const entries = await loadQueueEntries();
  return entries.filter((entry) => {
    if (entry.status === "synced" || entry.status === "failed") {
      return false;
    }

    if (entry.status === "retrying") {
      return entry.attemptCount < MAX_RETRY_ATTEMPTS;
    }

    return true;
  });
}

export async function markQueueEntriesRetrying(
  ids: string[],
  error?: string | null,
  now = new Date(),
): Promise<CodexQueueEntry[]> {
  const idSet = new Set(ids);
  const timestamp = getNowIso(now);
  const entries = await loadQueueEntries();
  const nextEntries = entries.map((entry) => {
    if (!idSet.has(entry.id)) {
      return entry;
    }

    return {
      ...entry,
      status: "retrying" as const,
      attemptCount: entry.attemptCount + 1,
      lastAttemptAt: timestamp,
      lastError: error ?? entry.lastError,
      updatedAt: timestamp,
    };
  });

  await saveQueueEntries(nextEntries);
  return nextEntries;
}

export async function markQueueEntriesSynced(ids: string[]): Promise<CodexQueueEntry[]> {
  const idSet = new Set(ids);
  const nextEntries = (await loadQueueEntries()).filter((entry) => !idSet.has(entry.id));
  await saveQueueEntries(nextEntries);
  return nextEntries;
}

export async function recordQueueFailure(
  ids: string[],
  error: string,
  now = new Date(),
): Promise<CodexQueueEntry[]> {
  const idSet = new Set(ids);
  const timestamp = getNowIso(now);
  const entries = await loadQueueEntries();
  const nextEntries = entries.map((entry) => {
    if (!idSet.has(entry.id)) {
      return entry;
    }

    return {
      ...entry,
      status:
        entry.attemptCount >= MAX_RETRY_ATTEMPTS ? ("failed" as const) : ("retrying" as const),
      lastFailureAt: timestamp,
      lastError: error,
      updatedAt: timestamp,
    };
  });

  await saveQueueEntries(nextEntries);
  return nextEntries;
}

export async function getQueueStats(): Promise<CodexQueueStats> {
  const entries = await loadQueueEntries();

  return {
    total: entries.length,
    pending: entries.filter((entry) => entry.status === "pending").length,
    retrying: entries.filter((entry) => entry.status === "retrying").length,
    failed: entries.filter((entry) => entry.status === "failed").length,
  };
}
