import { createClient, type SupabaseClient } from "@supabase/supabase-js";
import type { Database } from "@zest/types/database";
import { loadAuthSession, type PersistedAuthSession } from "../auth/session";
import { SUPABASE_ANON_KEY, SUPABASE_URL } from "../config/constants";

// Temporary backend transport: reuses the existing Supabase write path so
// Codex can ship on the same ingestion flow as Claude. We expect to replace this
// with authenticated requests to api.meetzest.com once the dedicated API is ready.
export interface OnDemandClient {
  client: SupabaseClient<Database>;
  dispose: () => Promise<void>;
}

export interface CreateOnDemandClientOptions {
  createClientImpl?: typeof createClient<Database>;
  loadSession?: () => Promise<PersistedAuthSession | null>;
  supabaseAnonKey?: string;
  supabaseUrl?: string;
}

function createSupabaseClientInstance(
  createClientImpl: typeof createClient<Database>,
  supabaseUrl: string,
  supabaseAnonKey: string,
): SupabaseClient<Database> {
  return createClientImpl(supabaseUrl, supabaseAnonKey, {
    auth: {
      autoRefreshToken: true,
      persistSession: false,
    },
  });
}

export async function createOnDemandClient(
  options: CreateOnDemandClientOptions = {},
): Promise<OnDemandClient | null> {
  const createClientImpl = options.createClientImpl ?? createClient<Database>;
  const loadSession = options.loadSession ?? loadAuthSession;
  const supabaseUrl = options.supabaseUrl ?? SUPABASE_URL;
  const supabaseAnonKey = options.supabaseAnonKey ?? SUPABASE_ANON_KEY;

  if (!supabaseUrl || !supabaseAnonKey) {
    return null;
  }

  const session = await loadSession();
  if (!session) {
    return null;
  }

  const client = createSupabaseClientInstance(createClientImpl, supabaseUrl, supabaseAnonKey);
  const { error } = await client.auth.setSession({
    access_token: session.accessToken,
    refresh_token: session.refreshToken,
  });

  if (error) {
    return null;
  }

  return {
    client,
    dispose: async () => {
      await client.removeAllChannels();
    },
  };
}
