import { dirname } from "node:path";
import {
  type ExclusionReason,
  PrivacyService as PrivacyServiceImpl,
  type ProcessResult,
} from "@zest/privacy-redaction";
import type {
  ChatMessageInsert,
  ChatSessionInsert,
  CodexPreparedTranscriptPayload,
  CodexSanitizedFieldSummary,
  CodexSanitizedPayloadMetadata,
  CodexSanitizedPayloadResult,
} from "../types/zest-payload";
import { createNodeFsAdapter } from "./node-fs-adapter";

function createPrivacyServiceForSource(sourcePath: string): PrivacyServiceImpl {
  return new PrivacyServiceImpl({
    enableCache: true,
    fs: createNodeFsAdapter(dirname(sourcePath)),
  });
}

function mapFieldSummary(
  field: CodexSanitizedFieldSummary["field"],
  result: ProcessResult,
): CodexSanitizedFieldSummary {
  return {
    detectionCount: result.detections.length,
    field,
    patterns: [...new Set(result.detections.map((detection) => detection.pattern))].sort(),
    wasRedacted: result.wasRedacted,
  };
}

function sanitizeSessionTitle(
  session: ChatSessionInsert,
  service: PrivacyServiceImpl,
  summaries: CodexSanitizedFieldSummary[],
  sourcePath: string,
): ChatSessionInsert {
  if (!session.title) {
    return session;
  }

  const result = service.processContent(session.title, sourcePath);
  if (result.hasSensitiveData) {
    summaries.push(mapFieldSummary("session.title", result));
  }

  return {
    ...session,
    title: result.content,
  };
}

function sanitizeMessages(
  messages: ChatMessageInsert[],
  service: PrivacyServiceImpl,
  summaries: CodexSanitizedFieldSummary[],
  sourcePath: string,
): ChatMessageInsert[] {
  return messages.map((message) => {
    const result = service.processContent(message.content, sourcePath);
    if (result.hasSensitiveData) {
      summaries.push(mapFieldSummary(`messages.${message.message_index}.content`, result));
    }

    return {
      ...message,
      content: result.content,
    };
  });
}

function createDroppedResult(
  input: CodexPreparedTranscriptPayload,
  droppedReason: NonNullable<CodexSanitizedPayloadMetadata["droppedReason"]>,
  details: Partial<CodexSanitizedPayloadMetadata> = {},
): CodexSanitizedPayloadResult {
  return {
    status: "dropped",
    payload: input.payload,
    privacy: input.privacy,
    metadata: {
      fields: [],
      droppedReason,
      ...details,
    },
  };
}

export async function sanitizeNormalizedPayload(
  input: CodexPreparedTranscriptPayload,
): Promise<CodexSanitizedPayloadResult> {
  if (input.privacy.sourceKind !== "transcript") {
    return createDroppedResult(input, "unsupported_source");
  }

  if (!input.privacy.sourcePathAllowlisted) {
    return createDroppedResult(input, "source_not_allowlisted");
  }

  const service = createPrivacyServiceForSource(input.privacy.sourcePath);
  await service.initialize();

  const exclusion = service.shouldExcludeFile(input.privacy.sourcePath);
  if (exclusion.excluded) {
    return createDroppedResult(input, "source_excluded", {
      exclusionMatch: exclusion.matchedRule,
      exclusionReason: exclusion.reason,
    });
  }

  const fields: CodexSanitizedFieldSummary[] = [];

  return {
    status: "sanitized",
    privacy: input.privacy,
    payload: {
      ...input.payload,
      session: sanitizeSessionTitle(
        input.payload.session,
        service,
        fields,
        input.privacy.sourcePath,
      ),
      messages: sanitizeMessages(input.payload.messages, service, fields, input.privacy.sourcePath),
    },
    metadata: {
      fields,
    },
  };
}

export async function sanitizeNormalizedPayloads(
  inputs: CodexPreparedTranscriptPayload[],
): Promise<CodexSanitizedPayloadResult[]> {
  return Promise.all(inputs.map((input) => sanitizeNormalizedPayload(input)));
}

export function isSanitizedPayloadResult(
  result: CodexSanitizedPayloadResult,
): result is Extract<CodexSanitizedPayloadResult, { status: "sanitized" }> {
  return result.status === "sanitized";
}

export function getSanitizedPayloads(
  results: CodexSanitizedPayloadResult[],
): Extract<CodexSanitizedPayloadResult, { status: "sanitized" }>[] {
  return results.filter(isSanitizedPayloadResult);
}

export function formatExclusionReason(reason?: ExclusionReason): string | undefined {
  return reason;
}
