import { basename } from "node:path";
import type { SessionSignals } from "@zest/types/session-signals";
import { isAllowlistedCodexPath } from "../codex/paths";
import { PLATFORM_CODEX_APP, PLATFORM_TERMINAL, SOURCE } from "../config/constants";
import type { CodexSessionReference } from "../types/codex-session-reference";
import type { CodexParsedTranscript, CodexTranscriptMessage } from "../types/codex-transcript";
import type {
  ChatMessageInsert,
  ChatSessionInsert,
  CodexNormalizedTranscriptPayload,
  CodexPreparedTranscriptPayload,
} from "../types/zest-payload";

interface NormalizeTranscriptInput {
  transcript: CodexParsedTranscript;
  sessionRef?: CodexSessionReference;
  userId: string;
  workspaceId?: string | null;
}

interface NormalizeTranscriptsInput {
  transcripts: CodexParsedTranscript[];
  sessionRefsById?: Map<string, CodexSessionReference>;
  userId: string;
  workspaceId?: string | null;
}

function normalizeSignals(signals: SessionSignals): SessionSignals {
  return {
    mcp_usage: { ...signals.mcp_usage },
    skill_usage: {},
    agent_usage: { ...signals.agent_usage },
    builtin_usage: { ...signals.builtin_usage },
    unknown_usage: { ...signals.unknown_usage },
    image_count: signals.image_count,
  };
}

function resolveCreatedAt(transcript: CodexParsedTranscript): {
  createdAt: string;
  source: CodexNormalizedTranscriptPayload["decisions"]["createdAtSource"];
} {
  if (transcript.sessionMeta?.timestamp) {
    return { createdAt: transcript.sessionMeta.timestamp, source: "session_meta" };
  }

  const firstRecordTimestamp = transcript.records[0]?.timestamp;
  if (firstRecordTimestamp) {
    return { createdAt: firstRecordTimestamp, source: "first_record" };
  }

  return {
    createdAt: transcript.messages[0]?.timestamp ?? new Date(0).toISOString(),
    source: "first_message",
  };
}

function resolvePlatform(originator: string | undefined): {
  platform: string;
  source: CodexNormalizedTranscriptPayload["decisions"]["platformSource"];
} {
  if (originator === "Codex Desktop") {
    return {
      platform: PLATFORM_CODEX_APP,
      source: "originator",
    };
  }

  if (originator === "codex_cli_rs") {
    return {
      platform: PLATFORM_TERMINAL,
      source: "originator",
    };
  }

  return {
    platform: PLATFORM_TERMINAL,
    source: "fallback",
  };
}

function normalizeMessageContent(message: CodexTranscriptMessage): string {
  return message.textParts
    .map((part) => part.trim())
    .filter((part) => part.length > 0)
    .join("\n\n");
}

function normalizeMessageMetadata(message: CodexTranscriptMessage): ChatMessageInsert["metadata"] {
  const metadata: Record<string, string | number> = {};

  if (message.phase) {
    metadata.phase = message.phase;
  }

  metadata.source = message.source;
  metadata.line_number = message.lineNumber;

  return Object.keys(metadata).length > 0 ? metadata : null;
}

const CONVERSATIONAL_ROLES = new Set(["user", "assistant"]);

function normalizeMessages(transcript: CodexParsedTranscript, userId: string): ChatMessageInsert[] {
  return transcript.messages
    .filter((message) => CONVERSATIONAL_ROLES.has(message.role))
    .map((message) => ({
      role: message.role,
      content: normalizeMessageContent(message),
      created_at: message.timestamp,
      session_id: transcript.sessionId,
      user_id: userId,
      code_diffs: null,
      metadata: normalizeMessageMetadata(message),
      imageCount: message.imageCount,
    }))
    .filter((message) => message.content.length > 0 || message.imageCount > 0)
    .map(({ imageCount: _imageCount, ...message }, index) => ({
      ...message,
      message_index: index,
    }));
}

export function normalizeTranscriptToZestPayload(
  input: NormalizeTranscriptInput,
): CodexNormalizedTranscriptPayload {
  const { transcript, sessionRef, userId, workspaceId } = input;
  const { createdAt, source: createdAtSource } = resolveCreatedAt(transcript);
  const { platform, source: platformSource } = resolvePlatform(transcript.sessionMeta?.originator);
  const title = sessionRef?.title ?? null;

  const session: ChatSessionInsert = {
    id: transcript.sessionId,
    title,
    created_at: createdAt,
    user_id: userId,
    workspace_id: workspaceId ?? null,
    analysis_status: "pending",
    metadata: null,
    project_id: null,
    project_name: transcript.sessionMeta?.cwd ? basename(transcript.sessionMeta.cwd) : null,
    platform,
    source: SOURCE,
    signals: normalizeSignals(transcript.signals) as unknown as ChatSessionInsert["signals"],
  };

  return {
    session,
    messages: normalizeMessages(transcript, userId),
    decisions: {
      titleSource: sessionRef?.title ? "session_index" : "missing",
      createdAtSource,
      platformSource,
      sourceDetailsOmitted: true,
    },
  };
}

export function normalizeTranscriptToPreparedPayload(
  input: NormalizeTranscriptInput,
): CodexPreparedTranscriptPayload {
  const { transcript } = input;

  return {
    payload: normalizeTranscriptToZestPayload(input),
    privacy: {
      sourceKind: "transcript",
      sourcePath: transcript.filePath,
      sourcePathAllowlisted: isAllowlistedCodexPath(transcript.filePath),
    },
  };
}

export function normalizeTranscriptsToPreparedPayloads(
  input: NormalizeTranscriptsInput,
): CodexPreparedTranscriptPayload[] {
  const { transcripts, sessionRefsById, userId, workspaceId } = input;

  return transcripts.map((transcript) =>
    normalizeTranscriptToPreparedPayload({
      transcript,
      sessionRef: sessionRefsById?.get(transcript.sessionId),
      userId,
      workspaceId,
    }),
  );
}
