import { homedir } from "node:os";
import { isAbsolute, join, relative, resolve } from "node:path";

const DEFAULT_CODEX_DIR_NAME = ".codex";

const ALLOWLISTED_TOP_LEVEL_FILES = new Set([
  "config.toml",
  "session_index.jsonl",
  "history.jsonl",
]);

export function getCodexRootDir(): string {
  return process.env.ZEST_CODEX_ROOT_DIR ?? join(homedir(), DEFAULT_CODEX_DIR_NAME);
}

function isWithinRoot(rootDir: string, targetPath: string): boolean {
  const rel = relative(rootDir, targetPath);
  if (rel.length === 0) return false;
  return !(rel === ".." || rel.startsWith("../") || isAbsolute(rel));
}

function matchesAllowlist(relativePath: string): boolean {
  if (ALLOWLISTED_TOP_LEVEL_FILES.has(relativePath)) {
    return true;
  }

  if (relativePath.startsWith("sessions/") && relativePath.endsWith(".jsonl")) {
    const inner = relativePath.slice("sessions/".length);
    return inner.length > ".jsonl".length && !inner.includes("..");
  }

  return false;
}

export function resolveCodexPath(...segments: string[]): string {
  const rootDir = getCodexRootDir();
  const resolvedPath = resolve(rootDir, ...segments);

  if (!isWithinRoot(rootDir, resolvedPath)) {
    throw new Error(`Codex path must stay within ${rootDir}`);
  }

  const rel = relative(rootDir, resolvedPath);

  if (!matchesAllowlist(rel)) {
    throw new Error(`Codex path is not allowlisted: ${rel}`);
  }

  return resolvedPath;
}

export function isAllowlistedCodexPath(absolutePath: string): boolean {
  const rootDir = getCodexRootDir();

  if (!isWithinRoot(rootDir, absolutePath)) {
    return false;
  }

  return matchesAllowlist(relative(rootDir, absolutePath));
}
