import { appendFile, mkdir, open, readFile, rename, unlink } from "node:fs/promises";
import { basename, dirname, join } from "node:path";
import { parse as parseToml, stringify as stringifyToml } from "@iarna/toml";

const DIRECTORY_MODE = 0o700;
const FILE_MODE = 0o600;

type TomlValue = Parameters<typeof stringifyToml>[0];

async function ensureParentDirectory(filePath: string): Promise<void> {
  await mkdir(dirname(filePath), { recursive: true, mode: DIRECTORY_MODE });
}

async function writeFileAtomic(filePath: string, content: string): Promise<void> {
  await ensureParentDirectory(filePath);

  const temporaryFilePath = join(
    dirname(filePath),
    `.${basename(filePath)}.${process.pid}.${Date.now()}.tmp`,
  );

  let handle: Awaited<ReturnType<typeof open>> | undefined;

  try {
    handle = await open(temporaryFilePath, "w", FILE_MODE);
    await handle.writeFile(content, { encoding: "utf-8" });
    await handle.sync();
    await handle.close();
    handle = undefined;

    await rename(temporaryFilePath, filePath);
  } catch (error) {
    if (handle) {
      await handle.close().catch(() => undefined);
    }

    await unlink(temporaryFilePath).catch(() => undefined);
    throw error;
  }
}

export async function readJsonFile<T>(filePath: string): Promise<T | null> {
  try {
    const content = await readFile(filePath, "utf-8");
    return JSON.parse(content) as T;
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return null;
    }

    throw error;
  }
}

export async function writeJsonFileAtomic(filePath: string, value: unknown): Promise<void> {
  await writeFileAtomic(filePath, `${JSON.stringify(value, null, 2)}\n`);
}

export async function readTomlFile<T>(filePath: string): Promise<T | null> {
  try {
    const content = await readFile(filePath, "utf-8");
    return parseToml(content) as T;
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return null;
    }

    throw error;
  }
}

export async function writeTomlFileAtomic(filePath: string, value: TomlValue): Promise<void> {
  await writeFileAtomic(filePath, stringifyToml(value));
}

export async function removeStateFile(filePath: string): Promise<void> {
  try {
    await unlink(filePath);
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code !== "ENOENT") {
      throw error;
    }
  }
}

export async function appendTextFile(filePath: string, content: string): Promise<void> {
  await ensureParentDirectory(filePath);
  await appendFile(filePath, content, { encoding: "utf-8", mode: FILE_MODE });
}
