import type { SupabaseClient } from "@supabase/supabase-js";
import {
  type CollectionSettings,
  getEffectiveCollection,
  getEffectiveRetention,
  type RetentionSettings,
  WORKSPACE_COLLECTION_DEFAULTS,
  WORKSPACE_RETENTION_DEFAULTS,
} from "@zest/types";
import {
  collectionSettingsSchema,
  retentionSettingsSchema,
} from "@zest/types/data-controls-schemas";
import type { Database } from "@zest/types/database";

export const DATA_CONTROLS_CACHE_TTL_MS = 5 * 60 * 1000;

export class DataControlsProvider {
  private effectiveCollection: CollectionSettings | null = null;
  private effectiveRetention: RetentionSettings | null = null;
  private lastFetchedAt: number | null = null;
  private ready = false;

  public async refresh(
    client: SupabaseClient<Database>,
    workspaceId: string,
    userId: string,
    fetchedAt = Date.now(),
  ): Promise<boolean> {
    try {
      const [workspaceResult, userResult] = await Promise.all([
        client
          .from("workspace_data_controls")
          .select("collection, retention")
          .eq("workspace_id", workspaceId)
          .maybeSingle(),
        client
          .from("user_data_controls")
          .select("collection, retention")
          .eq("user_id", userId)
          .maybeSingle(),
      ]);

      if (workspaceResult.error || userResult.error) {
        return false;
      }

      const workspaceCollection = collectionSettingsSchema.safeParse(
        workspaceResult.data?.collection,
      );
      const workspaceRetention = retentionSettingsSchema.safeParse(workspaceResult.data?.retention);
      const userCollection = collectionSettingsSchema.safeParse(userResult.data?.collection);
      const userRetention = retentionSettingsSchema.safeParse(userResult.data?.retention);

      this.effectiveCollection = getEffectiveCollection(
        workspaceCollection.success ? workspaceCollection.data : WORKSPACE_COLLECTION_DEFAULTS,
        userCollection.success ? userCollection.data : null,
      );
      this.effectiveRetention = getEffectiveRetention(
        workspaceRetention.success ? workspaceRetention.data : WORKSPACE_RETENTION_DEFAULTS,
        userRetention.success ? userRetention.data : null,
      );
      this.lastFetchedAt = fetchedAt;
      this.ready = true;

      return true;
    } catch {
      return false;
    }
  }

  public isReady(): boolean {
    return this.ready;
  }

  public isStale(now = Date.now()): boolean {
    if (this.lastFetchedAt === null) {
      return true;
    }

    return now - this.lastFetchedAt > DATA_CONTROLS_CACHE_TTL_MS;
  }

  public invalidate(): void {
    this.effectiveCollection = null;
    this.effectiveRetention = null;
    this.lastFetchedAt = null;
    this.ready = false;
  }

  public shouldUploadUserMessages(): boolean {
    return this.effectiveCollection?.user_messages ?? false;
  }

  public shouldUploadAssistantMessages(): boolean {
    return this.effectiveCollection?.assistant_messages ?? false;
  }

  public shouldUploadCodeDiffs(): boolean {
    return this.effectiveCollection?.code_diffs ?? false;
  }

  public getCollection(): CollectionSettings | null {
    return this.effectiveCollection;
  }

  public getRetention(): RetentionSettings | null {
    return this.effectiveRetention;
  }
}
