import type {
  CodexCollaborationMode,
  CodexDuration,
  CodexGitContext,
  CodexMessageContentBlock,
  CodexRateLimitWindow,
  CodexSandboxPolicy,
  CodexTokenUsage,
} from "../../types/codex-transcript";
import {
  isArray,
  isBoolean,
  isNonEmptyString,
  isNumber,
  isRecord,
  isString,
  toStringArray,
} from "./guards";

export function parseDuration(value: unknown): CodexDuration | undefined {
  if (!isRecord(value)) {
    return undefined;
  }

  const secs = isNumber(value.secs) ? value.secs : undefined;
  const nanos = isNumber(value.nanos) ? value.nanos : undefined;

  if (secs === undefined && nanos === undefined) {
    return undefined;
  }

  return { ...(secs !== undefined ? { secs } : {}), ...(nanos !== undefined ? { nanos } : {}) };
}

export function parseTokenUsage(value: unknown): CodexTokenUsage | undefined {
  if (!isRecord(value)) {
    return undefined;
  }

  const inputTokens = isNumber(value.input_tokens) ? value.input_tokens : undefined;
  const cachedInputTokens = isNumber(value.cached_input_tokens)
    ? value.cached_input_tokens
    : undefined;
  const outputTokens = isNumber(value.output_tokens) ? value.output_tokens : undefined;
  const reasoningOutputTokens = isNumber(value.reasoning_output_tokens)
    ? value.reasoning_output_tokens
    : undefined;
  const totalTokens = isNumber(value.total_tokens) ? value.total_tokens : undefined;

  if (
    inputTokens === undefined &&
    cachedInputTokens === undefined &&
    outputTokens === undefined &&
    reasoningOutputTokens === undefined &&
    totalTokens === undefined
  ) {
    return undefined;
  }

  return {
    ...(inputTokens !== undefined ? { inputTokens } : {}),
    ...(cachedInputTokens !== undefined ? { cachedInputTokens } : {}),
    ...(outputTokens !== undefined ? { outputTokens } : {}),
    ...(reasoningOutputTokens !== undefined ? { reasoningOutputTokens } : {}),
    ...(totalTokens !== undefined ? { totalTokens } : {}),
  };
}

export function parseRateLimitWindow(value: unknown): CodexRateLimitWindow | undefined {
  if (!isRecord(value)) {
    return undefined;
  }

  const usedPercent = isNumber(value.used_percent) ? value.used_percent : undefined;
  const windowMinutes = isNumber(value.window_minutes) ? value.window_minutes : undefined;
  const resetsAt = isNumber(value.resets_at) ? value.resets_at : undefined;

  if (usedPercent === undefined && windowMinutes === undefined && resetsAt === undefined) {
    return undefined;
  }

  return {
    ...(usedPercent !== undefined ? { usedPercent } : {}),
    ...(windowMinutes !== undefined ? { windowMinutes } : {}),
    ...(resetsAt !== undefined ? { resetsAt } : {}),
  };
}

export function parseGitContext(value: unknown): CodexGitContext | undefined {
  if (!isRecord(value)) {
    return undefined;
  }

  const branch = isNonEmptyString(value.branch) ? value.branch : undefined;
  const commitHash = isNonEmptyString(value.commit_hash) ? value.commit_hash : undefined;
  const repositoryUrl = isNonEmptyString(value.repository_url) ? value.repository_url : undefined;

  if (branch === undefined && commitHash === undefined && repositoryUrl === undefined) {
    return undefined;
  }

  return {
    ...(branch ? { branch } : {}),
    ...(commitHash ? { commitHash } : {}),
    ...(repositoryUrl ? { repositoryUrl } : {}),
  };
}

export function parseSandboxPolicy(value: unknown): CodexSandboxPolicy | undefined {
  if (!isRecord(value) || !isNonEmptyString(value.type)) {
    return undefined;
  }

  return {
    type: value.type,
    writableRoots: toStringArray(value.writable_roots),
    ...(isBoolean(value.network_access) ? { networkAccess: value.network_access } : {}),
    ...(isBoolean(value.exclude_tmpdir_env_var)
      ? { excludeTmpdirEnvVar: value.exclude_tmpdir_env_var }
      : {}),
    ...(isBoolean(value.exclude_slash_tmp) ? { excludeSlashTmp: value.exclude_slash_tmp } : {}),
  };
}

export function parseCollaborationMode(value: unknown): CodexCollaborationMode | undefined {
  if (!isRecord(value) || !isNonEmptyString(value.mode)) {
    return undefined;
  }

  const settings = isRecord(value.settings) ? value.settings : undefined;

  return {
    mode: value.mode,
    ...(settings && isNonEmptyString(settings.model) ? { model: settings.model } : {}),
    ...(settings && isNonEmptyString(settings.reasoning_effort)
      ? { reasoningEffort: settings.reasoning_effort }
      : {}),
  };
}

export function parseMessageContentBlocks(value: unknown): CodexMessageContentBlock[] | null {
  if (!isArray(value)) {
    return null;
  }

  const blocks: CodexMessageContentBlock[] = [];

  for (const entry of value) {
    if (!isRecord(entry) || !isNonEmptyString(entry.type)) {
      return null;
    }

    if (entry.type === "input_text" || entry.type === "output_text") {
      if (!isString(entry.text)) {
        return null;
      }

      blocks.push({
        type: entry.type,
        text: entry.text,
      });
      continue;
    }

    if (entry.type === "input_image") {
      blocks.push({ type: "input_image" });
      continue;
    }

    return null;
  }

  return blocks;
}
