declare const __ZEST_WEB_APP_URL__: string | undefined;
declare const __ZEST_SUPABASE_URL__: string | undefined;
declare const __ZEST_SUPABASE_ANON_KEY__: string | undefined;
declare const __ZEST_CODEX_DEBUG__: string | undefined;
declare const __ZEST_CODEX_ENABLE_LOGS__: string | undefined;

function resolveConfigValue({
  bundledValue,
  runtimeValue,
  fallback,
}: {
  bundledValue: string | undefined;
  runtimeValue: string | undefined;
  fallback: string;
}): string {
  if (typeof bundledValue === "string" && bundledValue.length > 0) {
    return bundledValue;
  }

  if (typeof runtimeValue === "string" && runtimeValue.length > 0) {
    return runtimeValue;
  }

  return fallback;
}

export const CLIENT_ID = "codex-cli";
export const WEB_APP_URL = resolveConfigValue({
  bundledValue: typeof __ZEST_WEB_APP_URL__ !== "undefined" ? __ZEST_WEB_APP_URL__ : undefined,
  runtimeValue: process.env.ZEST_WEB_APP_URL,
  fallback: "http://localhost:3000",
});
export const SUPABASE_URL = resolveConfigValue({
  bundledValue: typeof __ZEST_SUPABASE_URL__ !== "undefined" ? __ZEST_SUPABASE_URL__ : undefined,
  runtimeValue: process.env.ZEST_SUPABASE_URL,
  fallback: "",
});
export const SUPABASE_ANON_KEY = resolveConfigValue({
  bundledValue:
    typeof __ZEST_SUPABASE_ANON_KEY__ !== "undefined" ? __ZEST_SUPABASE_ANON_KEY__ : undefined,
  runtimeValue: process.env.ZEST_SUPABASE_ANON_KEY,
  fallback: "",
});
export const DEBUG_MODE_ENABLED =
  resolveConfigValue({
    bundledValue: typeof __ZEST_CODEX_DEBUG__ !== "undefined" ? __ZEST_CODEX_DEBUG__ : undefined,
    runtimeValue: process.env.ZEST_CODEX_DEBUG,
    fallback: "",
  }) === "1";
export const SYNC_DEBUG_LOGGING_ENABLED =
  resolveConfigValue({
    bundledValue:
      typeof __ZEST_CODEX_ENABLE_LOGS__ !== "undefined" ? __ZEST_CODEX_ENABLE_LOGS__ : undefined,
    runtimeValue: process.env.ZEST_CODEX_ENABLE_LOGS,
    fallback: "",
  }) === "1";
export const PLATFORM_TERMINAL = "terminal";
export const PLATFORM_CODEX_APP = "codex-app";
export const SOURCE = "codex";

export const DEVICE_AUTH_INITIATE_PATH = "/api/auth/device/initiate";
export const DEVICE_AUTH_POLL_PATH = "/api/auth/device/poll";
