import type {
  CodexEventRecord,
  CodexResponseItemRecord,
  CodexTranscriptMessage,
} from "../../types/codex-transcript";

export function messageFromEvent(record: CodexEventRecord): CodexTranscriptMessage | null {
  if (record.eventType === "user_message") {
    return {
      role: "user",
      textParts: [record.message, ...record.textElements].filter((entry) => entry.length > 0),
      imageCount: record.imagesCount + record.localImagesCount,
      timestamp: record.timestamp,
      lineNumber: record.lineNumber,
      source: "event_msg",
    };
  }

  if (record.eventType === "agent_message") {
    return {
      role: "assistant",
      ...(record.phase ? { phase: record.phase } : {}),
      textParts: record.message.length > 0 ? [record.message] : [],
      imageCount: 0,
      timestamp: record.timestamp,
      lineNumber: record.lineNumber,
      source: "event_msg",
    };
  }

  return null;
}

export function messageFromResponseItem(
  record: CodexResponseItemRecord,
): CodexTranscriptMessage | null {
  if (record.itemType !== "message") {
    return null;
  }

  return {
    role: record.role,
    ...(record.phase ? { phase: record.phase } : {}),
    textParts: record.content.flatMap((block) => (block.text ? [block.text] : [])),
    imageCount: record.content.filter((block) => block.type === "input_image").length,
    timestamp: record.timestamp,
    lineNumber: record.lineNumber,
    source: "response_item",
  };
}
