import { createReadStream } from "node:fs";
import readline from "node:readline";
import type {
  CodexSessionReference,
  HistoryEntry,
  SessionIndexEntry,
} from "../types/codex-session-reference";

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function isFiniteNumber(value: unknown): value is number {
  return typeof value === "number" && Number.isFinite(value);
}

async function readJsonLines<T>(
  filePath: string,
  parseLine: (value: unknown) => T | null,
): Promise<T[]> {
  const stream = createReadStream(filePath, { encoding: "utf-8" });
  const lines = readline.createInterface({
    crlfDelay: Number.POSITIVE_INFINITY,
    input: stream,
  });
  const entries: T[] = [];

  try {
    for await (const rawLine of lines) {
      const line = rawLine.trim();
      if (line.length === 0) {
        continue;
      }

      let parsed: unknown;
      try {
        parsed = JSON.parse(line);
      } catch {
        continue;
      }

      const entry = parseLine(parsed);
      if (entry !== null) {
        entries.push(entry);
      }
    }
  } finally {
    lines.close();
    stream.destroy();
  }

  return entries;
}

function parseSessionIndexEntry(value: unknown): SessionIndexEntry | null {
  if (!isRecord(value) || !isNonEmptyString(value.id) || !isNonEmptyString(value.updated_at)) {
    return null;
  }

  if (value.thread_name !== undefined && !isNonEmptyString(value.thread_name)) {
    return null;
  }

  return {
    id: value.id,
    ...(value.thread_name ? { threadName: value.thread_name } : {}),
    updatedAt: value.updated_at,
  };
}

function parseHistoryEntry(value: unknown): HistoryEntry | null {
  if (!isRecord(value)) {
    return null;
  }

  if (
    !isNonEmptyString(value.session_id) ||
    !isFiniteNumber(value.ts) ||
    !isNonEmptyString(value.text)
  ) {
    return null;
  }

  return {
    sessionId: value.session_id,
    text: value.text,
    timestamp: value.ts,
  };
}

export async function readSessionIndex(filePath: string): Promise<SessionIndexEntry[]> {
  return readJsonLines(filePath, parseSessionIndexEntry);
}

export async function readHistory(filePath: string): Promise<HistoryEntry[]> {
  return readJsonLines(filePath, parseHistoryEntry);
}

export async function buildSessionReferences(input: {
  sessionIndexPath: string;
  historyPath: string;
}): Promise<CodexSessionReference[]> {
  const [sessionIndexEntries, historyEntries] = await Promise.all([
    readSessionIndex(input.sessionIndexPath),
    readHistory(input.historyPath),
  ]);

  const latestHistoryBySessionId = new Map<
    string,
    {
      timestamp: number;
      text: string;
    }
  >();

  for (const entry of historyEntries) {
    const existing = latestHistoryBySessionId.get(entry.sessionId);
    if (!existing || entry.timestamp >= existing.timestamp) {
      latestHistoryBySessionId.set(entry.sessionId, {
        text: entry.text,
        timestamp: entry.timestamp,
      });
    }
  }

  return sessionIndexEntries.map((entry) => {
    const latestHistory = latestHistoryBySessionId.get(entry.id);

    return {
      ...(latestHistory
        ? {
            latestPromptAt: new Date(latestHistory.timestamp * 1000).toISOString(),
            latestPromptText: latestHistory.text,
          }
        : {}),
      ...(entry.threadName ? { title: entry.threadName } : {}),
      sessionId: entry.id,
      updatedAt: entry.updatedAt,
    };
  });
}

export function buildSessionReferenceMap(
  references: CodexSessionReference[],
): Map<string, CodexSessionReference> {
  return new Map(references.map((reference) => [reference.sessionId, reference]));
}
