import type { SessionSignals } from "@zest/types/session-signals";
import type {
  CodexParsedTranscript,
  CodexResponseCustomToolCallRecord,
  CodexResponseFunctionCallRecord,
  CodexResponseMessageRecord,
  CodexResponseWebSearchCallRecord,
  CodexTranscriptRecord,
} from "../types/codex-transcript";

const BUILTIN_FUNCTION_CALL_NAMES = new Set([
  "Bash",
  "Read",
  "Edit",
  "Write",
  "MultiEdit",
  "Glob",
  "Grep",
  "LS",
  "WebFetch",
  "WebSearch",
  "LSP",
  "NotebookEdit",
]);

const AGENT_FUNCTION_CALL_NAMES = new Set(["Task", "Agent"]);
const MCP_TOOL_NAME_PATTERN = /^mcp__[^_]+(?:_[^_]+)*__[^_]+(?:_[^_]+)*$/;

export const EMPTY_SIGNALS: SessionSignals = {
  mcp_usage: {},
  skill_usage: {},
  agent_usage: {},
  builtin_usage: {},
  unknown_usage: {},
  image_count: 0,
};

function incrementMap(map: Record<string, number>, key: string): void {
  map[key] = (map[key] ?? 0) + 1;
}

function recordFunctionCallSignal(
  record: CodexResponseFunctionCallRecord,
  signals: SessionSignals,
): void {
  if (MCP_TOOL_NAME_PATTERN.test(record.name)) {
    incrementMap(signals.mcp_usage, record.name);
    return;
  }

  if (BUILTIN_FUNCTION_CALL_NAMES.has(record.name)) {
    incrementMap(signals.builtin_usage, record.name);
    return;
  }

  if (AGENT_FUNCTION_CALL_NAMES.has(record.name)) {
    incrementMap(signals.agent_usage, record.name);
    return;
  }

  incrementMap(signals.unknown_usage, record.name);
}

function recordCustomToolSignal(
  record: CodexResponseCustomToolCallRecord,
  signals: SessionSignals,
): void {
  incrementMap(signals.builtin_usage, record.name);
}

function recordWebSearchSignal(
  _record: CodexResponseWebSearchCallRecord,
  signals: SessionSignals,
): void {
  incrementMap(signals.builtin_usage, "web_search");
}

function recordMessageSignal(record: CodexResponseMessageRecord, signals: SessionSignals): void {
  for (const block of record.content) {
    if (block.type === "input_image") {
      signals.image_count += 1;
    }
  }
}

export function extractSessionSignals(records: CodexTranscriptRecord[]): SessionSignals {
  const signals: SessionSignals = {
    mcp_usage: {},
    skill_usage: {},
    agent_usage: {},
    builtin_usage: {},
    unknown_usage: {},
    image_count: 0,
  };

  for (const record of records) {
    if (record.recordType !== "response_item") {
      continue;
    }

    switch (record.itemType) {
      case "function_call":
        recordFunctionCallSignal(record, signals);
        break;
      case "custom_tool_call":
        recordCustomToolSignal(record, signals);
        break;
      case "web_search_call":
        recordWebSearchSignal(record, signals);
        break;
      case "message":
        recordMessageSignal(record, signals);
        break;
      default:
        break;
    }
  }

  return signals;
}

export function summarizeSignalCounts(signals: SessionSignals): {
  mcpCalls: number;
  builtinCalls: number;
  agentCalls: number;
  unknownCalls: number;
} {
  return {
    mcpCalls: sumUsageMap(signals.mcp_usage),
    builtinCalls: sumUsageMap(signals.builtin_usage),
    agentCalls: sumUsageMap(signals.agent_usage),
    unknownCalls: sumUsageMap(signals.unknown_usage),
  };
}

function sumUsageMap(map: Record<string, number>): number {
  return Object.values(map).reduce((total, count) => total + count, 0);
}

export function withSignals(
  transcript: Omit<CodexParsedTranscript, "signals">,
): CodexParsedTranscript {
  return {
    ...transcript,
    signals: extractSessionSignals(transcript.records),
  };
}
