import { readJsonFile, removeStateFile, writeJsonFileAtomic } from "../state/files";
import { resolveStatePath } from "../state/paths";

export const AUTH_SESSION_VERSION = 1;

export interface PersistedAuthSession {
  version: typeof AUTH_SESSION_VERSION;
  accessToken: string;
  refreshToken: string;
  userId: string;
  email: string;
  refreshTokenExpiresAt?: number;
}

export function getAuthSessionFilePath(): string {
  return resolveStatePath("auth", "session.json");
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

export function isAuthSessionValid(value: unknown): value is PersistedAuthSession {
  if (!value || typeof value !== "object") {
    return false;
  }

  const candidate = value as Partial<PersistedAuthSession>;

  if (candidate.version !== AUTH_SESSION_VERSION) {
    return false;
  }

  if (
    !isNonEmptyString(candidate.accessToken) ||
    !isNonEmptyString(candidate.refreshToken) ||
    !isNonEmptyString(candidate.userId) ||
    !isNonEmptyString(candidate.email)
  ) {
    return false;
  }

  if (
    candidate.refreshTokenExpiresAt !== undefined &&
    (typeof candidate.refreshTokenExpiresAt !== "number" ||
      !Number.isFinite(candidate.refreshTokenExpiresAt))
  ) {
    return false;
  }

  return true;
}

export async function loadAuthSession(): Promise<PersistedAuthSession | null> {
  const filePath = getAuthSessionFilePath();
  const session = await readJsonFile<unknown>(filePath);

  if (session === null) {
    return null;
  }

  if (!isAuthSessionValid(session)) {
    await removeStateFile(filePath);
    return null;
  }

  return session;
}

export async function saveAuthSession(session: PersistedAuthSession): Promise<void> {
  await writeJsonFileAtomic(getAuthSessionFilePath(), session);
}

export async function clearAuthSession(): Promise<void> {
  await removeStateFile(getAuthSessionFilePath());
}
