import { mkdir } from "node:fs/promises";
import { homedir } from "node:os";
import { isAbsolute, join, relative, resolve } from "node:path";
import pluginManifest from "../../.codex-plugin/plugin.json";

const DEFAULT_STATE_DIR_NAME = `.codex-${pluginManifest.name}`;
const DIRECTORY_MODE = 0o700;

export function getDefaultStateRootDir(): string {
  return join(homedir(), DEFAULT_STATE_DIR_NAME);
}

export function getStateRootDir(): string {
  return process.env.ZEST_CODEX_STATE_DIR ?? getDefaultStateRootDir();
}

export function resolveStatePath(...segments: string[]): string {
  const stateRootDir = getStateRootDir();
  const resolvedPath = resolve(stateRootDir, ...segments);
  const relativePath = relative(stateRootDir, resolvedPath);

  if (relativePath.length === 0) {
    return resolvedPath;
  }

  if (relativePath === ".." || relativePath.startsWith(`..${"/"}`) || isAbsolute(relativePath)) {
    throw new Error(`State path must stay within ${stateRootDir}`);
  }

  return resolvedPath;
}

export async function ensureStateRootDir(): Promise<string> {
  const stateRootDir = getStateRootDir();
  await mkdir(stateRootDir, { recursive: true, mode: DIRECTORY_MODE });
  return stateRootDir;
}

export function resolveDefaultStatePath(...segments: string[]): string {
  const stateRootDir = getDefaultStateRootDir();
  const resolvedPath = resolve(stateRootDir, ...segments);
  const relativePath = relative(stateRootDir, resolvedPath);

  if (relativePath.length === 0) {
    return resolvedPath;
  }

  if (relativePath === ".." || relativePath.startsWith(`..${"/"}`) || isAbsolute(relativePath)) {
    throw new Error(`State path must stay within ${stateRootDir}`);
  }

  return resolvedPath;
}
