// Retention period presets
export const RETENTION_PERIODS = ["12h", "1d", "7d", "30d", "90d", "1y", "forever"] as const;
export type RetentionPeriod = (typeof RETENTION_PERIODS)[number];

// Data categories
export const DATA_CATEGORIES = ["user_messages", "assistant_messages", "code_diffs"] as const;
export type DataCategory = (typeof DATA_CATEGORIES)[number];

// Human-readable labels for UI
export const DATA_CATEGORY_LABELS: Record<DataCategory, { label: string; description: string }> = {
  user_messages: { label: "User messages", description: "AI prompts and questions" },
  assistant_messages: { label: "Assistant messages", description: "AI responses and suggestions" },
  code_diffs: { label: "Code diffs", description: "Before/after code changes" },
};

export const RETENTION_PERIOD_LABELS: Record<RetentionPeriod, string> = {
  "12h": "12 hours",
  "1d": "1 day",
  "7d": "7 days",
  "30d": "30 days",
  "90d": "90 days",
  "1y": "1 year",
  forever: "Forever",
};

// Retention period ordering for MIN comparison (lower index = shorter)
export const RETENTION_PERIOD_ORDER: Record<RetentionPeriod, number> = {
  "12h": 0,
  "1d": 1,
  "7d": 2,
  "30d": 3,
  "90d": 4,
  "1y": 5,
  forever: 6,
};

// Collection settings type (matches collectionSettingsSchema in data-controls-schemas.ts)
export type CollectionSettings = {
  user_messages: boolean;
  assistant_messages: boolean;
  code_diffs: boolean;
};

// Retention settings type (matches retentionSettingsSchema in data-controls-schemas.ts)
export type RetentionSettings = {
  user_messages: RetentionPeriod;
  assistant_messages: RetentionPeriod;
  code_diffs: RetentionPeriod;
};

// Workspace defaults (used when no row exists)
export const WORKSPACE_COLLECTION_DEFAULTS: CollectionSettings = {
  user_messages: true,
  assistant_messages: true,
  code_diffs: true,
};

export const WORKSPACE_RETENTION_DEFAULTS: RetentionSettings = {
  user_messages: "90d",
  assistant_messages: "90d",
  code_diffs: "7d",
};

/**
 * Compare two retention periods, return the shorter one.
 * Used for merge logic: effective = MIN(workspace, user).
 */
export function shorterRetentionPeriod(a: RetentionPeriod, b: RetentionPeriod): RetentionPeriod {
  return RETENTION_PERIOD_ORDER[a] <= RETENTION_PERIOD_ORDER[b] ? a : b;
}

/**
 * Merge workspace + user collection settings.
 * User can only restrict (AND logic) — never relax.
 */
export function getEffectiveCollection(
  workspace: CollectionSettings,
  user: CollectionSettings | null,
): CollectionSettings {
  if (!user) return workspace;
  return {
    user_messages: workspace.user_messages && user.user_messages,
    assistant_messages: workspace.assistant_messages && user.assistant_messages,
    code_diffs: workspace.code_diffs && user.code_diffs,
  };
}

/**
 * Merge workspace + user retention settings.
 * User can only shorten (MIN logic) — never extend.
 */
export function getEffectiveRetention(
  workspace: RetentionSettings,
  user: RetentionSettings | null,
): RetentionSettings {
  if (!user) return workspace;
  return {
    user_messages: shorterRetentionPeriod(workspace.user_messages, user.user_messages),
    assistant_messages: shorterRetentionPeriod(
      workspace.assistant_messages,
      user.assistant_messages,
    ),
    code_diffs: shorterRetentionPeriod(workspace.code_diffs, user.code_diffs),
  };
}

/** Maps each retention preset to days. `null` means "never delete" (forever). */
export const RETENTION_PERIOD_DAYS: Record<RetentionPeriod, number | null> = {
  "12h": 0.5,
  "1d": 1,
  "7d": 7,
  "30d": 30,
  "90d": 90,
  "1y": 365,
  forever: null,
};

export type CategoryStatus = "available" | "partially_deleted" | "fully_deleted";

export interface CategoryAvailability {
  category: DataCategory;
  status: CategoryStatus;
  retentionPeriod: RetentionPeriod;
}

/**
 * Given a standup's date range and the user's effective retention settings,
 * computes per-category data availability using date math only.
 *
 * Three statuses:
 *   available          — entire range is within retention window
 *   partially_deleted  — dateFrom is outside window but dateTo is inside
 *   fully_deleted      — entire range is outside retention window
 *
 * NOTE: collection settings are intentionally excluded — they only gate future
 * ingestion. Past data exists regardless of whether collection is currently on.
 */
export function computeCategoryAvailability(
  standupDateFrom: string,
  standupDateTo: string,
  effectiveRetention: RetentionSettings,
): CategoryAvailability[] {
  const now = new Date();
  const dateFrom = new Date(standupDateFrom);
  const dateTo = new Date(standupDateTo);

  return DATA_CATEGORIES.map((category) => {
    const retentionPeriod = effectiveRetention[category];
    const days = RETENTION_PERIOD_DAYS[retentionPeriod];

    if (days === null) {
      return { category, status: "available", retentionPeriod };
    }

    const cutoff = new Date(now.getTime() - days * 24 * 60 * 60 * 1000);

    if (dateTo < cutoff) {
      return { category, status: "fully_deleted", retentionPeriod };
    }
    if (dateFrom < cutoff) {
      return { category, status: "partially_deleted", retentionPeriod };
    }
    return { category, status: "available", retentionPeriod };
  });
}
