import { z } from "zod";
import { RETENTION_PERIODS } from "./data-controls.ts";

// Collection settings schema
export const collectionSettingsSchema = z.object({
  user_messages: z.boolean(),
  assistant_messages: z.boolean(),
  code_diffs: z.boolean(),
});

// Retention settings schema
export const retentionSettingsSchema = z.object({
  user_messages: z.enum(RETENTION_PERIODS),
  assistant_messages: z.enum(RETENTION_PERIODS),
  code_diffs: z.enum(RETENTION_PERIODS),
});
