import { loadAuthSession, type PersistedAuthSession } from "../auth/session";
import { type CodexRuntimeDiscoveryResult, discoverCodexRuntimeFiles } from "../codex/discovery";
import { buildSessionReferenceMap, buildSessionReferences } from "../collector/session-references";
import { readTranscripts } from "../collector/transcript-parser";
import { sanitizeNormalizedPayloads } from "../privacy/sanitize";
import type { CodexSessionReference } from "../types/codex-session-reference";
import type { CodexSanitizedPayloadResult } from "../types/zest-payload";
import { loadWorkspaceBinding, type PersistedWorkspaceBinding } from "../workspace/binding";
import { normalizeTranscriptsToPreparedPayloads } from "./normalize";
import { enqueueSanitizedPayloads } from "./queue";
import {
  type CodexSyncErrorType,
  type UploadQueuedTranscriptsResult,
  uploadQueuedTranscripts,
} from "./upload";

export type SyncPhase = "completed" | "queued_only";

export interface SyncResponse {
  success: boolean;
  phase?: SyncPhase;
  collection: {
    discoveredTranscripts: number;
    parsedTranscripts: number;
    queued: number;
    dropped: number;
  };
  uploaded: {
    messages: number;
    sessions: number;
  };
  errorType?: CodexSyncErrorType;
  message: string;
}

export interface RunSyncDependencies {
  discover?: () => Promise<CodexRuntimeDiscoveryResult>;
  enqueue?: (results: CodexSanitizedPayloadResult[], now?: Date) => Promise<unknown>;
  loadSession?: () => Promise<PersistedAuthSession | null>;
  loadWorkspace?: () => Promise<PersistedWorkspaceBinding | null>;
  readSessionReferences?: (input: {
    historyPath: string;
    sessionIndexPath: string;
  }) => Promise<CodexSessionReference[]>;
  readTranscripts?: (filePaths: string[]) => ReturnType<typeof readTranscripts>;
  sanitize?: typeof sanitizeNormalizedPayloads;
  upload?: () => Promise<UploadQueuedTranscriptsResult>;
}

function createCollectionSummary(overrides: Partial<SyncResponse["collection"]> = {}) {
  return {
    discoveredTranscripts: 0,
    dropped: 0,
    parsedTranscripts: 0,
    queued: 0,
    ...overrides,
  };
}

function formatSyncMessage(result: {
  collection: SyncResponse["collection"];
  errorType?: CodexSyncErrorType;
  phase?: SyncPhase;
  uploaded: SyncResponse["uploaded"];
}): string {
  const base = `Discovered ${result.collection.discoveredTranscripts} transcript(s), parsed ${result.collection.parsedTranscripts}, queued ${result.collection.queued}, dropped ${result.collection.dropped}.`;

  if (result.phase === "completed") {
    return `${base} Uploaded ${result.uploaded.sessions} session(s) and ${result.uploaded.messages} message(s).`;
  }

  if (result.phase === "queued_only" && result.errorType) {
    return `${base} Upload deferred: ${result.errorType}.`;
  }

  return base;
}

function resolveSyncPhase(
  uploadResult: UploadQueuedTranscriptsResult,
  collection: SyncResponse["collection"],
): SyncPhase | undefined {
  if (uploadResult.success) {
    return "completed";
  }

  if (collection.queued > 0) {
    return "queued_only";
  }

  return undefined;
}

function resolveSyncMessage(input: {
  collection: SyncResponse["collection"];
  phase?: SyncPhase;
  uploadResult: UploadQueuedTranscriptsResult;
}): string {
  const { collection, phase, uploadResult } = input;

  if (uploadResult.success) {
    return formatSyncMessage({
      collection,
      phase: "completed",
      uploaded: uploadResult.uploaded,
    });
  }

  if (phase === "queued_only") {
    return formatSyncMessage({
      collection,
      errorType: uploadResult.errorType,
      phase,
      uploaded: uploadResult.uploaded,
    });
  }

  return uploadResult.error ?? "Sync failed.";
}

export async function runSync(dependencies: RunSyncDependencies = {}): Promise<SyncResponse> {
  const discover = dependencies.discover ?? discoverCodexRuntimeFiles;
  const loadSession = dependencies.loadSession ?? loadAuthSession;
  const loadWorkspace = dependencies.loadWorkspace ?? loadWorkspaceBinding;
  const readSessionReferences = dependencies.readSessionReferences ?? buildSessionReferences;
  const readAllTranscripts = dependencies.readTranscripts ?? readTranscripts;
  const sanitize = dependencies.sanitize ?? sanitizeNormalizedPayloads;
  const enqueue = dependencies.enqueue ?? enqueueSanitizedPayloads;
  const upload = dependencies.upload ?? (() => uploadQueuedTranscripts());

  const runtime = await discover();
  const collection = createCollectionSummary({
    discoveredTranscripts: runtime.transcriptPaths.length,
  });

  if (runtime.transcriptPaths.length === 0) {
    const response: SyncResponse = {
      success: true,
      phase: "completed",
      collection,
      uploaded: {
        messages: 0,
        sessions: 0,
      },
      message: "Sync completed: no transcripts found.",
    };

    return response;
  }

  const session = await loadSession();
  if (!session) {
    return {
      success: false,
      collection,
      uploaded: {
        messages: 0,
        sessions: 0,
      },
      errorType: "not_authenticated",
      message: "Sync failed before collection: not authenticated.",
    };
  }

  const workspace = await loadWorkspace();
  const sessionRefs =
    runtime.sessionIndexPath && runtime.historyPath
      ? await readSessionReferences({
          historyPath: runtime.historyPath,
          sessionIndexPath: runtime.sessionIndexPath,
        })
      : [];
  const transcripts = await readAllTranscripts(runtime.transcriptPaths);
  collection.parsedTranscripts = transcripts.length;

  const prepared = normalizeTranscriptsToPreparedPayloads({
    transcripts,
    sessionRefsById: buildSessionReferenceMap(sessionRefs),
    userId: session.userId,
    workspaceId: workspace?.active.id ?? null,
  });
  const sanitized = await sanitize(prepared);
  collection.dropped = sanitized.filter((result) => result.status === "dropped").length;
  collection.queued = sanitized.filter((result) => result.status === "sanitized").length;

  await enqueue(sanitized);

  const uploadResult = await upload();
  const phase = resolveSyncPhase(uploadResult, collection);
  const response: SyncResponse = {
    success: uploadResult.success,
    ...(phase ? { phase } : {}),
    collection,
    uploaded: uploadResult.uploaded,
    ...(uploadResult.errorType ? { errorType: uploadResult.errorType } : {}),
    message: resolveSyncMessage({
      collection,
      phase,
      uploadResult,
    }),
  };

  return response;
}
