import { readTomlFile, removeStateFile, writeTomlFileAtomic } from "../state/files";
import { resolveStatePath } from "../state/paths";

export const WORKSPACE_BINDING_VERSION = 1;

export interface PersistedWorkspaceBinding {
  version: typeof WORKSPACE_BINDING_VERSION;
  active: {
    id: string;
    name?: string;
  };
  sync?: {
    enabled: boolean;
  };
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

export function getWorkspaceBindingFilePath(): string {
  return resolveStatePath("workspace", "binding.toml");
}

export function isWorkspaceBindingValid(value: unknown): value is PersistedWorkspaceBinding {
  if (!value || typeof value !== "object") {
    return false;
  }

  const candidate = value as Partial<PersistedWorkspaceBinding>;

  if (candidate.version !== WORKSPACE_BINDING_VERSION) {
    return false;
  }

  if (!candidate.active || typeof candidate.active !== "object") {
    return false;
  }

  if (!isNonEmptyString(candidate.active.id)) {
    return false;
  }

  if (candidate.active.name !== undefined && !isNonEmptyString(candidate.active.name)) {
    return false;
  }

  if (candidate.sync !== undefined) {
    if (!candidate.sync || typeof candidate.sync !== "object") {
      return false;
    }

    if (typeof candidate.sync.enabled !== "boolean") {
      return false;
    }
  }

  return true;
}

export async function loadWorkspaceBinding(): Promise<PersistedWorkspaceBinding | null> {
  const filePath = getWorkspaceBindingFilePath();
  const binding = await readTomlFile<unknown>(filePath);

  if (binding === null) {
    return null;
  }

  if (!isWorkspaceBindingValid(binding)) {
    await removeStateFile(filePath);
    return null;
  }

  return binding;
}

export async function saveWorkspaceBinding(binding: PersistedWorkspaceBinding): Promise<void> {
  await writeTomlFileAtomic(getWorkspaceBindingFilePath(), {
    active: {
      ...(binding.active.name ? { name: binding.active.name } : {}),
      id: binding.active.id,
    },
    ...(binding.sync ? { sync: { enabled: binding.sync.enabled } } : {}),
    version: binding.version,
  });
}

export async function saveActiveWorkspaceBinding(workspaceId: string): Promise<void> {
  await saveWorkspaceBinding({
    active: {
      id: workspaceId,
    },
    version: WORKSPACE_BINDING_VERSION,
  });
}

export async function clearWorkspaceBinding(): Promise<void> {
  await removeStateFile(getWorkspaceBindingFilePath());
}
