import { DEBUG_MODE_ENABLED } from "../config/constants";
import { readJsonFile, removeStateFile, writeJsonFileAtomic } from "../state/files";
import { resolveStatePath } from "../state/paths";

export const UPDATE_CHECK_CACHE_VERSION = 1;
export const UPDATE_CHECK_ERROR = "best_effort_check_failed";
export const UPDATE_CHECK_TTL_MS = 6 * 60 * 60 * 1000;
export const UPDATE_CHECK_TIMEOUT_MS = 2_000;
export const UPDATE_REPOSITORY_URL = "https://github.com/Winding-Labs/zest-codex";
export const UPDATE_PACKAGE_URL =
  "https://raw.githubusercontent.com/Winding-Labs/zest-codex/main/package.json";
export const DEBUG_UPDATE_PACKAGE_URL = "http://127.0.0.1:8787/package.json";

export interface RemoteUpdatePackage {
  homepage?: string;
  publishedAt?: string;
  repository?:
    | string
    | {
        type?: string;
        url?: string;
      };
  version: string;
}

export interface UpdateMetadata {
  available: boolean;
  checkedAt: string;
  latestVersion?: string;
  downloadUrl?: string;
  publishedAt?: string;
  error?: typeof UPDATE_CHECK_ERROR;
}

interface PersistedUpdateCheck {
  version: typeof UPDATE_CHECK_CACHE_VERSION;
  expiresAt: number;
  result: UpdateMetadata;
}

type FetchImplementation = typeof fetch;

export interface GetBestEffortUpdateMetadataOptions {
  currentVersion: string;
  fetchImplementation?: FetchImplementation;
  now?: number;
  packageUrl?: string;
  repositoryUrl?: string;
  timeoutMs?: number;
  ttlMs?: number;
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function normalizeIsoTimestamp(value: unknown): string | undefined {
  if (!isNonEmptyString(value)) {
    return undefined;
  }

  const timestamp = Date.parse(value);
  return Number.isNaN(timestamp) ? undefined : new Date(timestamp).toISOString();
}

function isUpdateMetadata(value: unknown): value is UpdateMetadata {
  if (!value || typeof value !== "object") {
    return false;
  }

  const candidate = value as Partial<UpdateMetadata>;

  if (typeof candidate.available !== "boolean" || !isNonEmptyString(candidate.checkedAt)) {
    return false;
  }

  if (candidate.latestVersion !== undefined && !isNonEmptyString(candidate.latestVersion)) {
    return false;
  }

  if (candidate.downloadUrl !== undefined && !isNonEmptyString(candidate.downloadUrl)) {
    return false;
  }

  if (candidate.publishedAt !== undefined && !isNonEmptyString(candidate.publishedAt)) {
    return false;
  }

  if (candidate.error !== undefined && candidate.error !== UPDATE_CHECK_ERROR) {
    return false;
  }

  return true;
}

function isPersistedUpdateCheck(value: unknown): value is PersistedUpdateCheck {
  if (!value || typeof value !== "object") {
    return false;
  }

  const candidate = value as Partial<PersistedUpdateCheck>;

  if (
    candidate.version !== UPDATE_CHECK_CACHE_VERSION ||
    typeof candidate.expiresAt !== "number" ||
    !Number.isFinite(candidate.expiresAt)
  ) {
    return false;
  }

  return isUpdateMetadata(candidate.result);
}

function getFetchImplementation(fetchImplementation?: FetchImplementation): FetchImplementation {
  const implementation = fetchImplementation ?? globalThis.fetch;

  if (!implementation) {
    throw new Error("Global fetch is not available");
  }

  return implementation;
}

function normalizeRepositoryUrl(repository: RemoteUpdatePackage["repository"]): string | undefined {
  if (isNonEmptyString(repository)) {
    return repository.trim();
  }

  if (!repository || typeof repository !== "object") {
    return undefined;
  }

  return isNonEmptyString(repository.url) ? repository.url.trim() : undefined;
}

function normalizePackage(remotePackage: unknown): RemoteUpdatePackage {
  if (!remotePackage || typeof remotePackage !== "object") {
    throw new Error("Invalid update package payload");
  }

  const candidate = remotePackage as Partial<RemoteUpdatePackage>;

  if (!isNonEmptyString(candidate.version)) {
    throw new Error("Update package is missing version");
  }

  return {
    ...(isNonEmptyString(candidate.homepage) ? { homepage: candidate.homepage.trim() } : {}),
    ...(normalizeIsoTimestamp(candidate.publishedAt)
      ? { publishedAt: normalizeIsoTimestamp(candidate.publishedAt) }
      : {}),
    ...(normalizeRepositoryUrl(candidate.repository)
      ? { repository: normalizeRepositoryUrl(candidate.repository) }
      : {}),
    version: candidate.version.trim(),
  };
}

function parseVersion(version: string): {
  main: [number, number, number];
  prerelease: string[];
} | null {
  const match = version.trim().match(/^(\d+)\.(\d+)\.(\d+)(?:-([0-9A-Za-z.-]+))?$/u);

  if (!match) {
    return null;
  }

  const [, major, minor, patch, prerelease] = match;

  return {
    main: [Number(major), Number(minor), Number(patch)],
    prerelease: prerelease ? prerelease.split(".") : [],
  };
}

function compareIdentifiers(left: string, right: string): number {
  const leftIsNumeric = /^\d+$/u.test(left);
  const rightIsNumeric = /^\d+$/u.test(right);

  if (leftIsNumeric && rightIsNumeric) {
    return Number(left) - Number(right);
  }

  if (leftIsNumeric) {
    return -1;
  }

  if (rightIsNumeric) {
    return 1;
  }

  return left.localeCompare(right);
}

export function compareVersions(currentVersion: string, latestVersion: string): number | null {
  const current = parseVersion(currentVersion);
  const latest = parseVersion(latestVersion);

  if (!current || !latest) {
    return null;
  }

  for (let index = 0; index < current.main.length; index += 1) {
    const difference = current.main[index] - latest.main[index];

    if (difference !== 0) {
      return difference;
    }
  }

  if (current.prerelease.length === 0 && latest.prerelease.length === 0) {
    return 0;
  }

  if (current.prerelease.length === 0) {
    return 1;
  }

  if (latest.prerelease.length === 0) {
    return -1;
  }

  const length = Math.max(current.prerelease.length, latest.prerelease.length);

  for (let index = 0; index < length; index += 1) {
    const left = current.prerelease[index];
    const right = latest.prerelease[index];

    if (left === undefined) {
      return -1;
    }

    if (right === undefined) {
      return 1;
    }

    const difference = compareIdentifiers(left, right);

    if (difference !== 0) {
      return difference;
    }
  }

  return 0;
}

export function getUpdateCheckCacheFilePath(): string {
  return resolveStatePath("update", "check.json");
}

async function loadCachedUpdateMetadata(now: number): Promise<UpdateMetadata | null> {
  const filePath = getUpdateCheckCacheFilePath();
  const cachedValue = await readJsonFile<unknown>(filePath);

  if (cachedValue === null) {
    return null;
  }

  if (!isPersistedUpdateCheck(cachedValue)) {
    await removeStateFile(filePath);
    return null;
  }

  if (cachedValue.expiresAt <= now) {
    return null;
  }

  return cachedValue.result;
}

async function saveCachedUpdateMetadata(result: UpdateMetadata, expiresAt: number): Promise<void> {
  await writeJsonFileAtomic(getUpdateCheckCacheFilePath(), {
    expiresAt,
    result,
    version: UPDATE_CHECK_CACHE_VERSION,
  });
}

async function fetchPackage(
  packageUrl: string,
  fetchImplementation: FetchImplementation,
  timeoutMs: number,
): Promise<RemoteUpdatePackage> {
  const response = await fetchImplementation(packageUrl, {
    headers: {
      Accept: "application/json",
    },
    signal: AbortSignal.timeout(timeoutMs),
  });

  if (!response.ok) {
    throw new Error(`Update package request failed with status ${response.status}`);
  }

  return normalizePackage(await response.json());
}

function createSuccessfulResult(
  checkedAt: string,
  currentVersion: string,
  remotePackage: RemoteUpdatePackage,
  repositoryUrl: string,
): UpdateMetadata {
  const comparison = compareVersions(currentVersion, remotePackage.version);

  if (comparison === null) {
    throw new Error("Unable to compare plugin versions");
  }

  return {
    available: comparison < 0,
    checkedAt,
    downloadUrl:
      remotePackage.homepage ?? normalizeRepositoryUrl(remotePackage.repository) ?? repositoryUrl,
    latestVersion: remotePackage.version,
    ...(remotePackage.publishedAt ? { publishedAt: remotePackage.publishedAt } : {}),
  };
}

function createFailureResult(checkedAt: string): UpdateMetadata {
  return {
    available: false,
    checkedAt,
    error: UPDATE_CHECK_ERROR,
  };
}

export async function getBestEffortUpdateMetadata(
  options: GetBestEffortUpdateMetadataOptions,
): Promise<UpdateMetadata | null> {
  if (process.env.ZEST_CODEX_UPDATE_CHECK_DISABLED === "1") {
    return null;
  }

  const now = options.now ?? Date.now();
  const cachedResult = await loadCachedUpdateMetadata(now);

  if (cachedResult) {
    return cachedResult;
  }

  const checkedAt = new Date(now).toISOString();
  const ttlMs = options.ttlMs ?? UPDATE_CHECK_TTL_MS;
  const packageUrl =
    options.packageUrl ??
    process.env.ZEST_CODEX_UPDATE_PACKAGE_URL ??
    (DEBUG_MODE_ENABLED ? DEBUG_UPDATE_PACKAGE_URL : UPDATE_PACKAGE_URL);

  try {
    const remotePackage = await fetchPackage(
      packageUrl,
      getFetchImplementation(options.fetchImplementation),
      options.timeoutMs ?? UPDATE_CHECK_TIMEOUT_MS,
    );
    const result = createSuccessfulResult(
      checkedAt,
      options.currentVersion,
      remotePackage,
      options.repositoryUrl ?? UPDATE_REPOSITORY_URL,
    );

    await saveCachedUpdateMetadata(result, now + ttlMs);
    return result;
  } catch {
    const result = createFailureResult(checkedAt);
    await saveCachedUpdateMetadata(result, now + ttlMs);
    return result;
  }
}
