import open from "open";
import {
  CLIENT_ID,
  DEVICE_AUTH_INITIATE_PATH,
  DEVICE_AUTH_POLL_PATH,
  WEB_APP_URL,
} from "../config/constants";
import { saveActiveWorkspaceBinding } from "../workspace/binding";
import { AUTH_SESSION_VERSION, type PersistedAuthSession, saveAuthSession } from "./session";

export interface LoginStartResult {
  authCode: string;
  deviceCode: string;
  verificationUrl: string;
  expiresIn: number;
  interval: number;
}

type LoginStatus = "pending" | "authorized";

interface DevicePollSession {
  access_token: string;
  refresh_token: string;
  refresh_token_expires_at?: number;
  refresh_token_expires_in?: number;
  workspace_id?: string;
  user: {
    id: string;
    email?: string;
  };
}

interface DevicePollResponse {
  status: LoginStatus;
  session?: DevicePollSession;
}

export interface LoginSuccessResult {
  status: "authenticated";
  email: string;
  userId: string;
  verificationUrl: string;
  deviceCode: string;
}

export interface LoginFailureResult {
  status: "failed";
  reason: "cancelled" | "expired" | "timeout" | "auth_error";
  message: string;
  verificationUrl: string;
  deviceCode: string;
}

export type LoginResult = LoginSuccessResult | LoginFailureResult;

type FetchImplementation = typeof fetch;

export interface LoginDependencies {
  clientId?: string;
  fetch?: FetchImplementation;
  openUrl?: (url: string) => Promise<unknown> | unknown;
  sleep?: (ms: number) => Promise<void>;
  webAppUrl?: string;
}

function getFetchImplementation(fetchImplementation?: FetchImplementation): FetchImplementation {
  const implementation = fetchImplementation ?? globalThis.fetch;

  if (!implementation) {
    throw new Error("Global fetch is not available");
  }

  return implementation;
}

function createUrl(baseUrl: string, path: string): string {
  return new URL(path, baseUrl).toString();
}

async function parseJsonResponse<T>(response: Response): Promise<T> {
  return (await response.json()) as T;
}

async function initiateDeviceLogin(
  fetchImplementation: FetchImplementation,
  webAppUrl: string,
  clientId: string,
): Promise<LoginStartResult> {
  const response = await fetchImplementation(createUrl(webAppUrl, DEVICE_AUTH_INITIATE_PATH), {
    body: JSON.stringify({ clientId }),
    headers: {
      "Content-Type": "application/json",
    },
    method: "POST",
  });

  if (!response.ok) {
    const errorPayload = await parseJsonResponse<{ error?: string }>(response).catch(() => null);
    throw new Error(errorPayload?.error || "Failed to initiate device login");
  }

  return parseJsonResponse<LoginStartResult>(response);
}

function normalizeAuthorizedSession(session: DevicePollSession): PersistedAuthSession {
  const email = session.user.email?.trim();

  if (!email) {
    throw new Error("Authorized session is missing a user email");
  }

  let refreshTokenExpiresAt: number | undefined;

  if (session.refresh_token_expires_at !== undefined) {
    refreshTokenExpiresAt = session.refresh_token_expires_at * 1000;
  } else if (session.refresh_token_expires_in !== undefined) {
    refreshTokenExpiresAt = Date.now() + session.refresh_token_expires_in * 1000;
  }

  return {
    accessToken: session.access_token,
    email,
    refreshToken: session.refresh_token,
    refreshTokenExpiresAt,
    userId: session.user.id,
    version: AUTH_SESSION_VERSION,
  };
}

function normalizeWorkspaceId(workspaceId: string | undefined): string | undefined {
  if (typeof workspaceId !== "string") {
    return undefined;
  }

  const trimmedWorkspaceId = workspaceId.trim();
  return trimmedWorkspaceId.length > 0 ? trimmedWorkspaceId : undefined;
}

function mapPollingError(message: string, start: LoginStartResult): LoginFailureResult | undefined {
  const normalizedMessage = message.toLowerCase();

  if (normalizedMessage.includes("denied")) {
    return {
      deviceCode: start.deviceCode,
      message: "Authorization was denied by the user.",
      reason: "cancelled",
      status: "failed",
      verificationUrl: start.verificationUrl,
    };
  }

  if (normalizedMessage.includes("expired")) {
    return {
      deviceCode: start.deviceCode,
      message: "The device code expired before authorization completed.",
      reason: "expired",
      status: "failed",
      verificationUrl: start.verificationUrl,
    };
  }

  return undefined;
}

export async function startLogin(dependencies: LoginDependencies = {}): Promise<LoginStartResult> {
  const fetchImplementation = getFetchImplementation(dependencies.fetch);
  const webAppUrl = dependencies.webAppUrl ?? WEB_APP_URL;
  const clientId = dependencies.clientId ?? CLIENT_ID;
  const start = await initiateDeviceLogin(fetchImplementation, webAppUrl, clientId);

  try {
    await Promise.resolve((dependencies.openUrl ?? open)(start.verificationUrl));
  } catch {
    // Best-effort browser launch only. The returned device code and URL are enough to continue.
  }

  return start;
}

export async function completeLogin(
  start: LoginStartResult,
  dependencies: LoginDependencies = {},
): Promise<LoginResult> {
  const fetchImplementation = getFetchImplementation(dependencies.fetch);
  const webAppUrl = dependencies.webAppUrl ?? WEB_APP_URL;
  const sleep =
    dependencies.sleep ?? ((ms: number) => new Promise((resolve) => setTimeout(resolve, ms)));
  const maxAttempts = Math.max(1, Math.floor(start.expiresIn / start.interval));

  for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
    try {
      const response = await fetchImplementation(createUrl(webAppUrl, DEVICE_AUTH_POLL_PATH), {
        body: JSON.stringify({ authCode: start.authCode }),
        headers: {
          "Content-Type": "application/json",
        },
        method: "POST",
      });

      if (!response.ok) {
        const errorPayload = await parseJsonResponse<{ error?: string }>(response).catch(
          () => null,
        );
        const failure = mapPollingError(
          errorPayload?.error || "Authentication polling failed",
          start,
        );

        if (failure) {
          return failure;
        }

        throw new Error(errorPayload?.error || "Authentication polling failed");
      }

      const payload = await parseJsonResponse<DevicePollResponse>(response);

      if (payload.status === "authorized" && payload.session) {
        const persistedSession = normalizeAuthorizedSession(payload.session);
        await saveAuthSession(persistedSession);
        const workspaceId = normalizeWorkspaceId(payload.session.workspace_id);

        if (workspaceId) {
          await saveActiveWorkspaceBinding(workspaceId);
        }

        return {
          deviceCode: start.deviceCode,
          email: persistedSession.email,
          status: "authenticated",
          userId: persistedSession.userId,
          verificationUrl: start.verificationUrl,
        };
      }

      if (payload.status === "pending" && attempt < maxAttempts - 1) {
        await sleep(start.interval * 1000);
      }
    } catch (error) {
      if (attempt === maxAttempts - 1) {
        return {
          deviceCode: start.deviceCode,
          message: error instanceof Error ? error.message : "Authentication polling failed",
          reason: "auth_error",
          status: "failed",
          verificationUrl: start.verificationUrl,
        };
      }

      await sleep(start.interval * 1000);
    }
  }

  return {
    deviceCode: start.deviceCode,
    message: "Authorization timed out before the device flow completed.",
    reason: "timeout",
    status: "failed",
    verificationUrl: start.verificationUrl,
  };
}

export async function loginWithDeviceFlow(
  dependencies: LoginDependencies = {},
): Promise<LoginResult> {
  const start = await startLogin(dependencies);
  return completeLogin(start, dependencies);
}
