import { access, readdir } from "node:fs/promises";
import { join, relative } from "node:path";
import { getCodexRootDir, isAllowlistedCodexPath, resolveCodexPath } from "./paths";

export interface CodexRuntimeDiscoveryResult {
  historyPath?: string;
  sessionIndexPath?: string;
  transcriptPaths: string[];
}

async function directoryExists(path: string): Promise<boolean> {
  try {
    await readdir(path);
    return true;
  } catch {
    return false;
  }
}

async function pathExists(path: string): Promise<boolean> {
  try {
    await access(path);
    return true;
  } catch {
    return false;
  }
}

function formatDatePath(now: Date): string {
  const year = String(now.getFullYear());
  const month = String(now.getMonth() + 1).padStart(2, "0");
  const day = String(now.getDate()).padStart(2, "0");
  return join("sessions", year, month, day);
}

function isCurrentDayTranscript(path: string, rootDir: string, now: Date): boolean {
  const relativePath = relative(rootDir, path);
  const currentDayPrefix = `${formatDatePath(now)}/`;
  return relativePath.startsWith(currentDayPrefix);
}

async function collectTranscriptPaths(dirPath: string): Promise<string[]> {
  const entries = await readdir(dirPath, { recursive: true, withFileTypes: true });
  const transcriptPaths: string[] = [];
  const rootDir = getCodexRootDir();
  const now = new Date();

  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.endsWith(".jsonl")) {
      continue;
    }

    const parentPath =
      typeof entry.parentPath === "string"
        ? entry.parentPath
        : "path" in entry && typeof entry.path === "string"
          ? join(dirPath, entry.path)
          : dirPath;
    const absolutePath = join(parentPath, entry.name);
    if (
      isAllowlistedCodexPath(absolutePath) &&
      isCurrentDayTranscript(absolutePath, rootDir, now)
    ) {
      transcriptPaths.push(absolutePath);
    }
  }

  return transcriptPaths.sort((left, right) => left.localeCompare(right));
}

export async function discoverCodexRuntimeFiles(): Promise<CodexRuntimeDiscoveryResult> {
  const rootDir = getCodexRootDir();
  const transcriptDir = join(rootDir, "sessions");
  const transcriptPaths = (await directoryExists(transcriptDir))
    ? await collectTranscriptPaths(transcriptDir)
    : [];

  const sessionIndexPath = resolveCodexPath("session_index.jsonl");
  const historyPath = resolveCodexPath("history.jsonl");

  return {
    ...((await pathExists(historyPath)) ? { historyPath } : {}),
    ...((await pathExists(sessionIndexPath)) ? { sessionIndexPath } : {}),
    transcriptPaths,
  };
}
